setControllerOf.source:
function setControllerOf(uint256 projectId, IERC165 controller) external override {
        // Keep a reference to the current controller.
        IERC165 currentController = controllerOf[projectId];

        // Enforce permissions.
        _requirePermissionAllowingOverrideFrom({
            account: PROJECTS.ownerOf(projectId),
            projectId: projectId,
            permissionId: JBPermissionIds.SET_CONTROLLER,
            alsoGrantAccessIf: (isAllowedToSetFirstController[msg.sender] && address(currentController) == address(0))
        });

        // The project must exist.
        if (projectId > PROJECTS.count()) revert JBDirectory_InvalidProjectIdInDirectory(projectId, PROJECTS.count());

        // Get a reference to a flag indicating whether the project is allowed to set its controller.
        // Setting the controller is allowed if the project doesn't have a controller,
        // OR if the current controller doesn't enforce access control,
        // OR if the project's ruleset allows setting the controller.
        bool allowSetController = address(currentController) == address(0)
            || !currentController.supportsInterface(type(IJBDirectoryAccessControl).interfaceId)
            ? true
            : IJBDirectoryAccessControl(address(currentController)).setControllerAllowed(projectId);

        // If setting the controller is not allowed, revert.
        if (!allowSetController) {
            revert JBDirectory_SetControllerNotAllowed({projectId: projectId});
        }

        // Prepare the new controller to receive the project.
        if (address(currentController) != address(0) && controller.supportsInterface(type(IJBMigratable).interfaceId)) {
            IJBMigratable(address(controller))
                .beforeReceiveMigrationFrom({from: currentController, projectId: projectId});
        }

        // Migrate if needed. The old controller's migrate() runs while the directory still points to it,
        // closing the reentrancy window where the directory would point to the new controller during migration.
        if (
            address(currentController) != address(0)
                && currentController.supportsInterface(type(IJBMigratable).interfaceId)
        ) {
            IJBMigratable(address(currentController)).migrate({projectId: projectId, to: controller});
        }

        // Set the new controller after migration completes.
        controllerOf[projectId] = controller;

        emit SetController({projectId: projectId, controller: controller, caller: msg.sender});

        // Notify the new controller that migration is complete and it is now the active controller.
        if (address(currentController) != address(0) && controller.supportsInterface(type(IJBMigratable).interfaceId)) {
            IJBMigratable(address(controller))
                .afterReceiveMigrationFrom({from: currentController, projectId: projectId});
        }
    }

setIsAllowedToSetFirstController.source:
function setIsAllowedToSetFirstController(address addr, bool flag) external override onlyOwner {
        // Set the flag in the allowlist.
        isAllowedToSetFirstController[addr] = flag;

        emit SetIsAllowedToSetFirstController({addr: addr, isAllowed: flag, caller: msg.sender});
    }

setPrimaryTerminalOf.source:
function setPrimaryTerminalOf(uint256 projectId, address token, IJBTerminal terminal) external override {
        // Enforce permissions.
        _requirePermissionFrom({
            account: PROJECTS.ownerOf(projectId),
            projectId: projectId,
            permissionId: JBPermissionIds.SET_PRIMARY_TERMINAL
        });

        // If the terminal doesn't accept the token, revert.
        if (terminal.accountingContextForTokenOf({projectId: projectId, token: token}).token == address(0)) {
            revert JBDirectory_TokenNotAccepted({projectId: projectId, token: token, terminal: terminal});
        }

        // If the terminal is not already in the project's terminal list, require ADD_TERMINALS permission.
        if (!isTerminalOf({projectId: projectId, terminal: terminal})) {
            _requirePermissionFrom({
                account: PROJECTS.ownerOf(projectId), projectId: projectId, permissionId: JBPermissionIds.ADD_TERMINALS
            });
        }

        // Implicit terminal addition is by design. A primary terminal must be in the terminals list;
        // implicit addition avoids requiring a separate addTerminalsOf call.
        _addTerminalIfNeeded({projectId: projectId, terminal: terminal});

        // Store the terminal as the project's primary terminal for the token.
        _primaryTerminalOf[projectId][token] = terminal;

        emit SetPrimaryTerminal({projectId: projectId, token: token, terminal: terminal, caller: msg.sender});
    }

setTerminalsOf.source:
function setTerminalsOf(uint256 projectId, IJBTerminal[] calldata terminals) external override {
        // Cache the controller to avoid redundant storage reads.
        IERC165 controller = controllerOf[projectId];

        // Enforce permissions.
        _requirePermissionAllowingOverrideFrom({
            account: PROJECTS.ownerOf(projectId),
            projectId: projectId,
            permissionId: JBPermissionIds.SET_TERMINALS,
            alsoGrantAccessIf: msg.sender == address(controller)
        });

        // Get a reference to the flag indicating whether the project is allowed to set its terminals.
        bool allowSetTerminals = !controller.supportsInterface(type(IJBDirectoryAccessControl).interfaceId)
            || IJBDirectoryAccessControl(address(controller)).setTerminalsAllowed(projectId);

        // If the caller is not the project's controller, the project's ruleset must allow setting terminals.
        if (msg.sender != address(controller) && !allowSetTerminals) {
            revert JBDirectory_SetTerminalsNotAllowed({projectId: projectId});
        }

        // Set the stored terminals for the project.
        _terminalsOf[projectId] = terminals;

        // If there are any duplicates, revert.
        if (terminals.length > 1) {
            for (uint256 i; i < terminals.length;) {
                for (uint256 j = i + 1; j < terminals.length;) {
                    if (terminals[i] == terminals[j]) revert JBDirectory_DuplicateTerminals(terminals[i]);
                    unchecked {
                        ++j;
                    }
                }
                unchecked {
                    ++i;
                }
            }
        }
        emit SetTerminals({projectId: projectId, terminals: terminals, caller: msg.sender});
    }

primaryTerminalOf.source:
function primaryTerminalOf(uint256 projectId, address token) external view override returns (IJBTerminal) {
        // Keep a reference to the primary terminal for the provided project ID and token.
        IJBTerminal primaryTerminal = _primaryTerminalOf[projectId][token];

        // If a primary terminal for the token was explicitly set and it's one of the project's terminals, return it.
        if (
            primaryTerminal != IJBTerminal(address(0))
                && isTerminalOf({projectId: projectId, terminal: primaryTerminal})
        ) {
            return primaryTerminal;
        }

        // Keep a storage reference to the project's terminals to avoid copying the array to memory.
        IJBTerminal[] storage terminals = _terminalsOf[projectId];

        // Keep a reference to the number of terminals the project has.
        uint256 numberOfTerminals = terminals.length;

        // Return the first terminal which accepts the specified token.
        for (uint256 i; i < numberOfTerminals;) {
            // Keep a reference to the terminal being iterated on.
            IJBTerminal terminal = terminals[i];

            // If the terminal accepts the specified token, return it.
            if (terminal.accountingContextForTokenOf({projectId: projectId, token: token}).token != address(0)) {
                return terminal;
            }
            unchecked {
                ++i;
            }
        }

        // Not found.
        return IJBTerminal(address(0));
    }

terminalsOf.source:
function terminalsOf(uint256 projectId) external view override returns (IJBTerminal[] memory) {
        return _terminalsOf[projectId];
    }

isTerminalOf.source:
function isTerminalOf(uint256 projectId, IJBTerminal terminal) public view override returns (bool) {
        // Keep a storage reference to the project's terminals to avoid copying the array to memory.
        IJBTerminal[] storage terminals = _terminalsOf[projectId];

        // Keep a reference to the number of terminals the project has.
        uint256 numberOfTerminals = terminals.length;

        // Loop through and return true if the terminal is found.
        for (uint256 i; i < numberOfTerminals;) {
            if (terminals[i] == terminal) return true;
            unchecked {
                ++i;
            }
        }

        // Otherwise, return false.
        return false;
    }

_addTerminalIfNeeded.source:
function _addTerminalIfNeeded(uint256 projectId, IJBTerminal terminal) internal {
        // Ensure that the terminal has not already been added.
        if (isTerminalOf({projectId: projectId, terminal: terminal})) return;

        // Keep a reference to the current controller.
        IERC165 controller = controllerOf[projectId];

        // Get a reference to a flag indicating whether the project is allowed to set its terminals.
        bool allowSetTerminals = !controller.supportsInterface(type(IJBDirectoryAccessControl).interfaceId)
            || IJBDirectoryAccessControl(address(controller)).setTerminalsAllowed(projectId);

        // The project's ruleset must allow setting terminals.
        if (!allowSetTerminals) {
            revert JBDirectory_SetTerminalsNotAllowed({projectId: projectId});
        }

        // Add the new terminal.
        _terminalsOf[projectId].push(terminal);

        emit AddTerminal({projectId: projectId, terminal: terminal, caller: msg.sender});
    }

recordAccountingContextOf.source:
function recordAccountingContextOf(uint256 projectId, JBAccountingContext[] calldata contexts) external override {
        // Get a reference to the project's current ruleset.
        JBRuleset memory ruleset = RULESETS.currentOf(projectId);

        // Make sure that if there's a ruleset, it allows adding accounting contexts.
        if (ruleset.id != 0 && !ruleset.allowAddAccountingContext()) {
            revert JBTerminalStore_AddingAccountingContextNotAllowed({
                projectId: projectId, rulesetId: ruleset.id, terminal: msg.sender
            });
        }

        // Record each accounting context.
        for (uint256 i; i < contexts.length;) {
            JBAccountingContext calldata context = contexts[i];

            // Make sure the token accounting context isn't already set.
            if (_accountingContextForTokenOf[msg.sender][projectId][context.token].token != address(0)) {
                revert JBTerminalStore_AccountingContextAlreadySet({token: context.token});
            }

            if (context.decimals > 36) {
                revert JBTerminalStore_AccountingContextDecimalsOutOfRange({
                    token: context.token, decimals: context.decimals
                });
            }

            // Keep track of a flag indicating if we know the provided decimals are incorrect.
            bool knownInvalidDecimals;
            uint256 expectedDecimals;

            // Check if the token is the native token and has the correct decimals.
            if (context.token == JBConstants.NATIVE_TOKEN && context.decimals != 18) {
                knownInvalidDecimals = true;
                expectedDecimals = 18;
            } else if (context.token != JBConstants.NATIVE_TOKEN && context.token.code.length > 0) {
                try IERC20Metadata(context.token).decimals() returns (uint8 decimals) {
                    expectedDecimals = decimals;
                } catch {
                    // The token didn't support `decimals`.
                    // @dev Non-standard ERC20s that revert on `decimals()` will bypass decimal validation.
                    // The caller is responsible for providing the correct decimals for such tokens.
                    knownInvalidDecimals = false;
                    expectedDecimals = context.decimals;
                }

                if (expectedDecimals > 36) {
                    revert JBTerminalStore_AccountingContextDecimalsOutOfRange({
                        token: context.token, decimals: expectedDecimals
                    });
                }

                if (context.decimals != expectedDecimals) knownInvalidDecimals = true;
            }

            // Make sure the decimals are correct.
            if (knownInvalidDecimals) {
                revert JBTerminalStore_AccountingContextDecimalsMismatch({
                    token: context.token, providedDecimals: context.decimals, expectedDecimals: expectedDecimals
                });
            }

            // Make sure the currency is non-zero.
            if (context.currency == 0) revert JBTerminalStore_ZeroAccountingContextCurrency({token: context.token});

            // Store the accounting context.
            _accountingContextForTokenOf[msg.sender][projectId][context.token] = context;

            // Add the context to the list.
            _accountingContextsOf[msg.sender][projectId].push(context);
            unchecked {
                ++i;
            }
        }
    }

recordAddedBalanceFor.source:
function recordAddedBalanceFor(uint256 projectId, address token, uint256 amount) external override {
        // Increment the balance.
        balanceOf[msg.sender][projectId][token] = balanceOf[msg.sender][projectId][token] + amount;
    }

recordCashOutFor.source:
function recordCashOutFor(
        address holder,
        uint256 projectId,
        uint256 cashOutCount,
        address tokenToReclaim,
        bool beneficiaryIsFeeless,
        bytes memory metadata
    )
        external
        override
        returns (
            JBRuleset memory ruleset,
            uint256 reclaimAmount,
            uint256 cashOutTaxRate,
            JBCashOutHookSpecification[] memory hookSpecifications
        )
    {
        (ruleset, reclaimAmount, cashOutTaxRate, hookSpecifications) = _computeCashOutFrom({
            terminal: msg.sender,
            holder: holder,
            projectId: projectId,
            cashOutCount: cashOutCount,
            tokenToReclaim: tokenToReclaim,
            beneficiaryIsFeeless: beneficiaryIsFeeless,
            metadata: metadata
        });

        // Compute the total amount to subtract from the project's balance.
        uint256 balanceDiff = reclaimAmount;

        if (hookSpecifications.length != 0) {
            uint256 numberOfSpecifications = hookSpecifications.length;
            for (uint256 i; i < numberOfSpecifications;) {
                uint256 specificationAmount = hookSpecifications[i].amount;
                if (specificationAmount != 0) {
                    balanceDiff += specificationAmount;
                }
                unchecked {
                    ++i;
                }
            }
        }

        // The selected terminal token can only pay out its own local surplus. Cash-out pricing may use shared surplus
        // across terminals/tokens, but settlement must not dip into this token's payout-limit reserve.
        JBAccountingContext memory accountingContext =
            _accountingContextForTokenOf[msg.sender][projectId][tokenToReclaim];
        uint256 localSurplus = _tokenSurplusFrom({
            terminal: msg.sender,
            projectId: projectId,
            accountingContext: accountingContext,
            ruleset: ruleset,
            targetDecimals: accountingContext.decimals,
            targetCurrency: accountingContext.currency
        });

        // The amount being reclaimed must be within the project's local surplus.
        if (balanceDiff > localSurplus) {
            revert JBTerminalStore_InadequateTerminalStoreBalance({amount: balanceDiff, balance: localSurplus});
        }

        // Remove the reclaimed funds from the project's balance.
        if (balanceDiff != 0) {
            unchecked {
                balanceOf[msg.sender][projectId][tokenToReclaim] -= balanceDiff;
            }
        }
    }

recordPaymentFrom.source:
function recordPaymentFrom(
        address payer,
        JBTokenAmount calldata amount,
        uint256 projectId,
        address beneficiary,
        bytes calldata metadata
    )
        external
        override
        returns (JBRuleset memory ruleset, uint256 tokenCount, JBPayHookSpecification[] memory hookSpecifications)
    {
        uint256 balanceDiff;
        (ruleset, tokenCount, hookSpecifications, balanceDiff) = _computePayFrom({
            terminal: msg.sender,
            payer: payer,
            amount: amount,
            projectId: projectId,
            beneficiary: beneficiary,
            metadata: metadata
        });

        // Add the correct balance difference to the token balance of the project.
        if (balanceDiff != 0) {
            // Cache the balance slot to avoid redundant storage reads.
            uint256 currentBalance = balanceOf[msg.sender][projectId][amount.token];
            balanceOf[msg.sender][projectId][amount.token] = currentBalance + balanceDiff;
        }
    }

recordPayoutFor.source:
function recordPayoutFor(
        uint256 projectId,
        address token,
        uint256 amount,
        uint256 currency
    )
        external
        override
        returns (JBRuleset memory ruleset, uint256 amountPaidOut)
    {
        // Look up the accounting context from storage.
        JBAccountingContext memory accountingContext = _accountingContextForTokenOf[msg.sender][projectId][token];

        // Get a reference to the project's current ruleset.
        ruleset = RULESETS.currentOf(projectId);

        // Get the payout limit for this currency.
        uint256 payoutLimit = IJBController(address(DIRECTORY.controllerOf(projectId))).FUND_ACCESS_LIMITS()
            .payoutLimitOf({
            projectId: projectId, rulesetId: ruleset.id, terminal: msg.sender, token: token, currency: currency
        });

        // Get the already-used payout limit for this cycle.
        uint256 usedPayoutLimit = usedPayoutLimitOf[msg.sender][projectId][token][ruleset.cycleNumber][currency];

        // Cap the amount to the remaining payout limit instead of reverting.
        uint256 remainingPayoutLimit = payoutLimit > usedPayoutLimit ? payoutLimit - usedPayoutLimit : 0;
        if (amount > remainingPayoutLimit) {
            amount = remainingPayoutLimit;
        }

        // If nothing can be paid out, return early with zero.
        if (amount == 0) {
            return (ruleset, 0);
        }

        // Convert the amount to the balance's currency.
        amountPaidOut = (currency == accountingContext.currency)
            ? amount
            : mulDiv({
                x: amount,
                y: 10 ** _MAX_FIXED_POINT_FIDELITY, // Use `_MAX_FIXED_POINT_FIDELITY` to keep as much of the
                // `_amount`'s fidelity as possible when converting.
                denominator: PRICES.pricePerUnitOf({
                    projectId: projectId,
                    pricingCurrency: currency,
                    unitCurrency: accountingContext.currency,
                    decimals: _MAX_FIXED_POINT_FIDELITY
                })
            });

        // If cross-currency conversion rounded to zero, return without consuming any payout limit. Otherwise a
        // permissionless caller could repeatedly request sub-unit payouts to drain the cycle's payout limit
        // without moving any funds.
        if (amountPaidOut == 0) {
            return (ruleset, 0);
        }

        // Cache the balance slot to avoid redundant storage reads.
        uint256 currentBalance = balanceOf[msg.sender][projectId][token];

        // The amount being paid out must be available.
        if (amountPaidOut > currentBalance) {
            revert JBTerminalStore_InadequateTerminalStoreBalance({amount: amountPaidOut, balance: currentBalance});
        }

        // Remove the paid out funds from the project's token balance.
        unchecked {
            balanceOf[msg.sender][projectId][token] = currentBalance - amountPaidOut;
        }

        // Store the new used payout limit.
        usedPayoutLimitOf[msg.sender][projectId][token][ruleset.cycleNumber][currency] = usedPayoutLimit + amount;
    }

recordTerminalMigration.source:
function recordTerminalMigration(uint256 projectId, address token) external override returns (uint256 balance) {
        // Get a reference to the project's current ruleset.
        JBRuleset memory ruleset = RULESETS.currentOf(projectId);

        // Terminal migration must be allowed.
        if (!ruleset.allowTerminalMigration()) {
            revert JBTerminalStore_TerminalMigrationNotAllowed({projectId: projectId, rulesetId: ruleset.id});
        }

        // Return the current balance, which is the amount being migrated.
        balance = balanceOf[msg.sender][projectId][token];

        // Set the balance to 0.
        balanceOf[msg.sender][projectId][token] = 0;
    }

recordUsedAllowanceOf.source:
function recordUsedAllowanceOf(
        uint256 projectId,
        address token,
        uint256 amount,
        uint256 currency
    )
        external
        override
        returns (JBRuleset memory ruleset, uint256 usedAmount)
    {
        // Look up the accounting context from storage.
        JBAccountingContext memory accountingContext = _accountingContextForTokenOf[msg.sender][projectId][token];

        // Get a reference to the project's current ruleset.
        ruleset = RULESETS.currentOf(projectId);

        // Convert the amount to this store's terminal's token.
        usedAmount = currency == accountingContext.currency
            ? amount
            : mulDiv({
                x: amount,
                y: 10 ** _MAX_FIXED_POINT_FIDELITY, // Use `_MAX_FIXED_POINT_FIDELITY` to keep as much of the
                // `amount`'s fidelity as possible when converting.
                denominator: PRICES.pricePerUnitOf({
                    projectId: projectId,
                    pricingCurrency: currency,
                    unitCurrency: accountingContext.currency,
                    decimals: _MAX_FIXED_POINT_FIDELITY
                })
            });

        // If a non-zero cross-currency conversion rounded to zero, return without consuming any surplus allowance.
        if (amount != 0 && currency != accountingContext.currency && usedAmount == 0) {
            return (ruleset, 0);
        }

        // Set the token being used as the only one to look for surplus within.
        JBAccountingContext[] memory accountingContexts = new JBAccountingContext[](1);
        accountingContexts[0] = accountingContext;

        uint256 surplus = _surplusFrom({
            terminal: msg.sender,
            projectId: projectId,
            accountingContexts: accountingContexts,
            ruleset: ruleset,
            targetDecimals: accountingContext.decimals,
            targetCurrency: accountingContext.currency
        });

        // The amount being used must be available in the surplus.
        if (usedAmount > surplus) revert JBTerminalStore_InadequateTerminalStoreBalance(usedAmount, surplus);

        // Get a reference to the new used surplus allowance for this ruleset ID.
        uint256 newUsedSurplusAllowanceOf =
            usedSurplusAllowanceOf[msg.sender][projectId][token][ruleset.id][currency] + amount;

        // There must be sufficient surplus allowance available.
        // Validate BEFORE writing to storage to avoid wasting gas on SSTORE when the tx will revert.
        uint256 surplusAllowance = IJBController(address(DIRECTORY.controllerOf(projectId))).FUND_ACCESS_LIMITS()
            .surplusAllowanceOf({
            projectId: projectId, rulesetId: ruleset.id, terminal: msg.sender, token: token, currency: currency
        });

        // Make sure the new used amount is within the allowance.
        if (newUsedSurplusAllowanceOf > surplusAllowance || surplusAllowance == 0) {
            revert JBTerminalStore_InadequateControllerAllowance({
                amount: newUsedSurplusAllowanceOf, allowance: surplusAllowance
            });
        }

        // Cache the balance slot to avoid redundant storage reads.
        uint256 currentBalance = balanceOf[msg.sender][projectId][token];

        // Update the project's balance.
        balanceOf[msg.sender][projectId][token] = currentBalance - usedAmount;

        // Store the incremented value.
        usedSurplusAllowanceOf[msg.sender][projectId][token][ruleset.id][currency] = newUsedSurplusAllowanceOf;
    }

