_cashOutWithDataHook.source:
function _cashOutWithDataHook(
        JBRuleset memory ruleset,
        JBBeforeCashOutRecordedContext memory context,
        uint256 surplus
    )
        internal
        view
        returns (uint256 reclaimAmount, uint256 cashOutTaxRate, JBCashOutHookSpecification[] memory hookSpecifications)
    {
        // Ask the data hook for the effective bonding curve parameters and any hook specifications.
        uint256 effectiveCashOutCount;
        uint256 effectiveTotalSupply;
        uint256 effectiveSurplusValue;
        (cashOutTaxRate, effectiveCashOutCount, effectiveTotalSupply, effectiveSurplusValue, hookSpecifications) =
            IJBRulesetDataHook(ruleset.dataHook()).beforeCashOutRecordedWith(context);

        // Noop specifications are informational only, so they can't also request forwarded funds.
        for (uint256 i; i < hookSpecifications.length;) {
            if (hookSpecifications[i].noop && hookSpecifications[i].amount != 0) {
                revert JBTerminalStore_NoopHookSpecHasAmount({amount: hookSpecifications[i].amount});
            }
            unchecked {
                ++i;
            }
        }

        // Apply the bonding curve to calculate how much of the surplus is reclaimable.
        if (surplus != 0) {
            reclaimAmount = JBCashOuts.cashOutFrom({
                surplus: effectiveSurplusValue,
                cashOutCount: effectiveCashOutCount,
                totalSupply: effectiveTotalSupply,
                cashOutTaxRate: cashOutTaxRate
            });

            // Cap at local surplus — can't reclaim more than what's locally available.
            if (reclaimAmount > surplus) reclaimAmount = surplus;
        }
    }

_computeCashOutFrom.source:
function _computeCashOutFrom(
        address terminal,
        address holder,
        uint256 projectId,
        uint256 cashOutCount,
        address tokenToReclaim,
        bool beneficiaryIsFeeless,
        bytes memory metadata
    )
        internal
        view
        returns (
            JBRuleset memory ruleset,
            uint256 reclaimAmount,
            uint256 cashOutTaxRate,
            JBCashOutHookSpecification[] memory hookSpecifications
        )
    {
        // Get a reference to the project's current ruleset.
        ruleset = RULESETS.currentOf(projectId);

        // Get the accounting context for the token being reclaimed.
        JBAccountingContext memory accountingContext = _accountingContextForTokenOf[terminal][projectId][tokenToReclaim];

        // Get the project's current surplus across ALL terminals and ALL tokens.
        uint256 surplus = JBSurplus.currentSurplusOf({
            projectId: projectId,
            terminals: DIRECTORY.terminalsOf(projectId),
            tokens: new address[](0),
            decimals: accountingContext.decimals,
            currency: accountingContext.currency
        });

        // Get the total number of outstanding project tokens.
        uint256 effectiveTotalSupply =
            IJBController(address(DIRECTORY.controllerOf(projectId))).totalTokenSupplyWithReservedTokensOf(projectId);

        // Can't cash out more tokens than are in the supply.
        if (cashOutCount > effectiveTotalSupply) {
            revert JBTerminalStore_InsufficientTokens({count: cashOutCount, totalSupply: effectiveTotalSupply});
        }

        // SECURITY NOTE: The data hook has absolute control over cash-out pricing.
        // It can set effectiveTotalSupply, effectiveCashOutCount, and cashOutTaxRate to arbitrary values,
        // completely overriding the terminal's bonding curve math. For example, setting
        // effectiveTotalSupply = surplus makes reclaimAmount = effectiveCashOutCount, bypassing the curve.
        // The terminal still burns the caller-supplied cashOutCount after pricing completes.
        // Project owners must review their data hooks with the same rigor as the terminal.

        // If the ruleset has a data hook which is enabled for cash outs, use it to derive a claim amount and memo.
        if (ruleset.useDataHookForCashOut() && ruleset.dataHook() != address(0)) {
            // Build the cash out context field-by-field — the struct has 11 fields, too many for a literal.
            JBBeforeCashOutRecordedContext memory context;
            context.terminal = terminal;
            context.holder = holder;
            context.projectId = projectId;
            context.rulesetId = ruleset.id;
            context.cashOutCount = cashOutCount;
            context.totalSupply = effectiveTotalSupply;
            context.surplus = JBTokenAmount({
                token: accountingContext.token,
                value: surplus,
                decimals: accountingContext.decimals,
                currency: accountingContext.currency
            });
            context.scopeCashOutsToLocalBalances = ruleset.scopeCashOutsToLocalBalances();
            context.cashOutTaxRate = ruleset.cashOutTaxRate();
            context.beneficiaryIsFeeless = beneficiaryIsFeeless;
            context.metadata = metadata;

            // Hook call + bonding curve in a helper to stay under the stack depth limit.
            (reclaimAmount, cashOutTaxRate, hookSpecifications) =
                _cashOutWithDataHook({ruleset: ruleset, context: context, surplus: surplus});
        } else {
            cashOutTaxRate = ruleset.cashOutTaxRate();

            // Apply the bonding curve to calculate how much of the surplus is reclaimable.
            if (surplus != 0) {
                reclaimAmount = JBCashOuts.cashOutFrom({
                    surplus: surplus,
                    cashOutCount: cashOutCount,
                    totalSupply: effectiveTotalSupply,
                    cashOutTaxRate: cashOutTaxRate
                });
            }
        }
    }

_computePayFrom.source:
function _computePayFrom(
        address terminal,
        address payer,
        JBTokenAmount memory amount,
        uint256 projectId,
        address beneficiary,
        bytes memory metadata
    )
        internal
        view
        returns (
            JBRuleset memory ruleset,
            uint256 tokenCount,
            JBPayHookSpecification[] memory hookSpecifications,
            uint256 balanceDiff
        )
    {
        // Get a reference to the project's current ruleset.
        ruleset = RULESETS.currentOf(projectId);

        // The project must have a ruleset.
        if (ruleset.cycleNumber == 0) revert JBTerminalStore_RulesetNotFound(projectId);

        // The ruleset must not have payments paused.
        if (ruleset.pausePay()) {
            revert JBTerminalStore_RulesetPaymentPaused({projectId: projectId, rulesetId: ruleset.id});
        }

        // The weight according to which new tokens are to be minted, as a fixed point number with 18 decimals.
        uint256 weight;

        // SECURITY NOTE: The data hook has absolute control over payment token minting.
        // It can return an arbitrary weight (overriding the ruleset's weight) and hook specifications
        // that divert payment funds to external hooks before they reach the project's balance.
        // Project owners must review their data hooks with the same rigor as the terminal.

        // If the ruleset has a data hook enabled for payments, use it to derive a weight and memo.
        if (ruleset.useDataHookForPay() && ruleset.dataHook() != address(0)) {
            // Create the pay context that'll be sent to the data hook.
            JBBeforePayRecordedContext memory context = JBBeforePayRecordedContext({
                terminal: terminal,
                payer: payer,
                amount: amount,
                projectId: projectId,
                rulesetId: ruleset.id,
                beneficiary: beneficiary,
                weight: ruleset.weight,
                reservedPercent: ruleset.reservedPercent(),
                metadata: metadata
            });

            (weight, hookSpecifications) = IJBRulesetDataHook(ruleset.dataHook()).beforePayRecordedWith(context);
        }
        // Otherwise use the ruleset's weight
        else {
            weight = ruleset.weight;
        }

        // Keep a reference to the amount that should be added to the project's balance.
        balanceDiff = amount.value;

        // Ensure that the specifications have valid amounts.
        for (uint256 i; i < hookSpecifications.length;) {
            if (hookSpecifications[i].noop && hookSpecifications[i].amount != 0) {
                revert JBTerminalStore_NoopHookSpecHasAmount({amount: hookSpecifications[i].amount});
            }

            uint256 specifiedAmount = hookSpecifications[i].amount;

            // Can't send more to hook than was paid.
            if (specifiedAmount != 0) {
                if (specifiedAmount > balanceDiff) {
                    revert JBTerminalStore_InvalidAmountToForwardHook({
                        amount: specifiedAmount, paidAmount: balanceDiff
                    });
                }

                // Decrement the total amount being added to the local balance.
                balanceDiff -= specifiedAmount;
            }
            unchecked {
                ++i;
            }
        }

        // If there's no amount being recorded, there's nothing left to do.
        if (amount.value == 0) return (ruleset, 0, hookSpecifications, 0);

        // If there's no weight, the token count must be 0, so there's nothing left to do.
        if (weight == 0) return (ruleset, 0, hookSpecifications, balanceDiff);

        // If the terminal should base its weight on a currency other than the terminal's currency, determine the
        // factor. The weight is always a fixed point number with 18 decimals. To ensure this, the ratio should use the
        // same
        // number of decimals as the `amount`.
        uint256 weightRatio = amount.currency == ruleset.baseCurrency()
            ? 10 ** amount.decimals
            : PRICES.pricePerUnitOf({
                projectId: projectId,
                pricingCurrency: amount.currency,
                unitCurrency: ruleset.baseCurrency(),
                decimals: amount.decimals
            });

        // Find the number of tokens to mint, as a fixed point number with as many decimals as `weight` has.
        tokenCount = mulDiv({x: amount.value, y: weight, denominator: weightRatio});
    }

_currentSurplusOf.source:
function _currentSurplusOf(
        uint256 projectId,
        IJBTerminal[] memory terminals,
        address[] memory tokens,
        uint256 decimals,
        uint256 currency
    )
        internal
        view
        returns (uint256 surplus)
    {
        // Fetch the ruleset once and delegate to the overload that accepts it.
        return _currentSurplusOf({
            projectId: projectId,
            terminals: terminals,
            tokens: tokens,
            decimals: decimals,
            currency: currency,
            ruleset: RULESETS.currentOf(projectId)
        });
    }

function _currentSurplusOf(
        uint256 projectId,
        IJBTerminal[] memory terminals,
        address[] memory tokens,
        uint256 decimals,
        uint256 currency,
        JBRuleset memory ruleset
    )
        internal
        view
        returns (uint256 surplus)
    {
        // If specific terminals were provided, use them. Otherwise, get all terminals from the directory.
        IJBTerminal[] memory resolvedTerminals = terminals.length != 0 ? terminals : DIRECTORY.terminalsOf(projectId);

        // Sum surplus across each terminal.
        for (uint256 i; i < resolvedTerminals.length;) {
            address terminal = address(resolvedTerminals[i]);

            // Build the list of accounting contexts to include in this terminal's surplus calculation.
            JBAccountingContext[] memory accountingContexts;
            if (tokens.length != 0) {
                // Specific tokens requested: look up each token's accounting context at this terminal.
                accountingContexts = new JBAccountingContext[](tokens.length);
                for (uint256 j; j < tokens.length;) {
                    accountingContexts[j] = _accountingContextForTokenOf[terminal][projectId][tokens[j]];
                    unchecked {
                        ++j;
                    }
                }
            } else {
                // No token filter: use all accounting contexts registered at this terminal.
                accountingContexts = _accountingContextsOf[terminal][projectId];
            }

            // Add this terminal's surplus (balance minus payout limits) converted to the target decimals/currency.
            surplus += _surplusFrom({
                terminal: terminal,
                projectId: projectId,
                accountingContexts: accountingContexts,
                ruleset: ruleset,
                targetDecimals: decimals,
                targetCurrency: currency
            });
            unchecked {
                ++i;
            }
        }
    }

_surplusFrom.source:
function _surplusFrom(
        address terminal,
        uint256 projectId,
        JBAccountingContext[] memory accountingContexts,
        JBRuleset memory ruleset,
        uint256 targetDecimals,
        uint256 targetCurrency
    )
        internal
        view
        returns (uint256 surplus)
    {
        // Keep a reference to the number of tokens being iterated on.
        uint256 numberOfTokenAccountingContexts = accountingContexts.length;

        // Add payout limits from each token.
        for (uint256 i; i < numberOfTokenAccountingContexts;) {
            uint256 tokenSurplus = _tokenSurplusFrom({
                terminal: terminal,
                projectId: projectId,
                accountingContext: accountingContexts[i],
                ruleset: ruleset,
                targetDecimals: targetDecimals,
                targetCurrency: targetCurrency
            });
            // Increment the surplus with any remaining balance.
            if (tokenSurplus > 0) surplus += tokenSurplus;
            unchecked {
                ++i;
            }
        }
    }

_tokenSurplusFrom.source:
function _tokenSurplusFrom(
        address terminal,
        uint256 projectId,
        JBAccountingContext memory accountingContext,
        JBRuleset memory ruleset,
        uint256 targetDecimals,
        uint256 targetCurrency
    )
        internal
        view
        returns (uint256 surplus)
    {
        // Keep a reference to the balance.
        surplus = balanceOf[terminal][projectId][accountingContext.token];

        // If needed, adjust the decimals of the fixed point number to have the correct decimals.
        surplus = accountingContext.decimals == targetDecimals
            ? surplus
            : JBFixedPointNumber.adjustDecimals({
                value: surplus, decimals: accountingContext.decimals, targetDecimals: targetDecimals
            });

        // Add up all the balances.
        surplus = (surplus == 0 || accountingContext.currency == targetCurrency)
            ? surplus
            : mulDiv({
                x: surplus,
                y: 10 ** _MAX_FIXED_POINT_FIDELITY, // Use `_MAX_FIXED_POINT_FIDELITY` to keep as much of the
                // surplus's fidelity as possible when converting.
                denominator: PRICES.pricePerUnitOf({
                    projectId: projectId,
                    pricingCurrency: accountingContext.currency,
                    unitCurrency: targetCurrency,
                    decimals: _MAX_FIXED_POINT_FIDELITY
                })
            });

        // Get a reference to the payout limit during the ruleset for the token.
        JBCurrencyAmount[] memory payoutLimits = IJBController(address(DIRECTORY.controllerOf(projectId)))
            .FUND_ACCESS_LIMITS()
            .payoutLimitsOf({
            projectId: projectId, rulesetId: ruleset.id, terminal: address(terminal), token: accountingContext.token
        });

        // Keep a reference to the number of payout limits being iterated on.
        uint256 numberOfPayoutLimits = payoutLimits.length;

        // Loop through each payout limit to determine the cumulative normalized payout limit remaining.
        for (uint256 i; i < numberOfPayoutLimits;) {
            JBCurrencyAmount memory payoutLimit = payoutLimits[i];

            // Set the payout limit value to the amount still available to pay out during the ruleset.
            {
                // Saturating subtraction: if a new ruleset activates with a lower payout limit than
                // what was already used under the previous limit, `used` can exceed `amount`. Clamping
                // to zero prevents an underflow revert that would DoS cash outs and surplus views.
                uint256 used = usedPayoutLimitOf[
                    terminal
                ][projectId][accountingContext.token][ruleset.cycleNumber][payoutLimit.currency];
                uint256 remaining = payoutLimit.amount > used ? payoutLimit.amount - used : 0;
                if (remaining > type(uint224).max) revert JBTerminalStore_Uint224Overflow(remaining);
                // forge-lint: disable-next-line(unsafe-typecast)
                payoutLimit.amount = uint224(remaining);
            }

            // Adjust the decimals of the fixed point number if needed to have the correct decimals.
            if (accountingContext.decimals != targetDecimals) {
                uint256 adjusted = JBFixedPointNumber.adjustDecimals({
                    value: payoutLimit.amount, decimals: accountingContext.decimals, targetDecimals: targetDecimals
                });
                if (adjusted > type(uint224).max) revert JBTerminalStore_Uint224Overflow(adjusted);
                // forge-lint: disable-next-line(unsafe-typecast)
                payoutLimit.amount = uint224(adjusted);
            }

            // Convert the `payoutLimit`'s amount to be in terms of the provided currency.
            if (payoutLimit.amount != 0 && payoutLimit.currency != targetCurrency) {
                uint256 converted = mulDiv({
                    x: payoutLimit.amount,
                    y: 10 ** _MAX_FIXED_POINT_FIDELITY, // Use `_MAX_FIXED_POINT_FIDELITY` to keep as much of the
                    // `payoutLimitRemaining`'s fidelity as possible when converting.
                    denominator: PRICES.pricePerUnitOf({
                        projectId: projectId,
                        pricingCurrency: payoutLimit.currency,
                        unitCurrency: targetCurrency,
                        decimals: _MAX_FIXED_POINT_FIDELITY
                    })
                });
                if (converted > type(uint224).max) revert JBTerminalStore_Uint224Overflow(converted);
                // forge-lint: disable-next-line(unsafe-typecast)
                payoutLimit.amount = uint224(converted);
            }

            // Decrement from the balance until it reaches zero.
            if (surplus > payoutLimit.amount) {
                surplus -= payoutLimit.amount;
            } else {
                return 0;
            }
            unchecked {
                ++i;
            }
        }
    }

burnFrom.source:
function burnFrom(address holder, uint256 projectId, uint256 count) external override onlyControllerOf(projectId) {
        // Get a reference to the project's current token.
        IJBToken token = tokenOf[projectId];

        // Get a reference to the amount of credits the holder has.
        uint256 creditBalance = creditBalanceOf[holder][projectId];

        // Get a reference to the amount of the project's current token the holder has in their wallet.
        uint256 tokenBalance = token == IJBToken(address(0)) ? 0 : token.balanceOf(holder);

        // There must be enough tokens to burn across the holder's combined token and credit balance.
        if (count > tokenBalance + creditBalance) {
            revert JBTokens_InsufficientTokensToBurn({count: count, tokenBalance: tokenBalance + creditBalance});
        }

        // The amount of tokens to burn.
        uint256 tokensToBurn;

        // Get a reference to how many tokens should be burned
        if (tokenBalance != 0) {
            // Burn credits before tokens.
            unchecked {
                tokensToBurn = creditBalance < count ? count - creditBalance : 0;
            }
        }

        // The amount of credits to burn.
        uint256 creditsToBurn;
        unchecked {
            creditsToBurn = count - tokensToBurn;
        }

        // Subtract the burned credits from the credit balance and credit supply.
        if (creditsToBurn > 0) {
            creditBalanceOf[holder][projectId] = creditBalanceOf[holder][projectId] - creditsToBurn;
            totalCreditSupplyOf[projectId] = totalCreditSupplyOf[projectId] - creditsToBurn;
        }

        emit Burn({
            holder: holder,
            projectId: projectId,
            count: count,
            creditBalance: creditBalance,
            tokenBalance: tokenBalance,
            caller: msg.sender
        });

        // Burn the tokens.
        if (tokensToBurn > 0) token.burn({account: holder, amount: tokensToBurn});
    }

claimTokensFor.source:
function claimTokensFor(
        address holder,
        uint256 projectId,
        uint256 count,
        address beneficiary
    )
        external
        override
        onlyControllerOf(projectId)
    {
        // Get a reference to the project's current token.
        IJBToken token = tokenOf[projectId];

        // The project must have a token contract attached.
        if (token == IJBToken(address(0))) revert JBTokens_TokenNotFound({projectId: projectId});

        // Get a reference to the amount of credits the holder has.
        uint256 creditBalance = creditBalanceOf[holder][projectId];

        // There must be enough credits to claim.
        if (count > creditBalance) revert JBTokens_InsufficientCredits(count, creditBalance);

        unchecked {
            // Subtract the claim amount from the holder's credit balance.
            creditBalanceOf[holder][projectId] = creditBalance - count;

            // Subtract the claim amount from the project's total credit supply.
            totalCreditSupplyOf[projectId] -= count;
        }

        emit ClaimTokens({
            holder: holder,
            projectId: projectId,
            creditBalance: creditBalance,
            count: count,
            beneficiary: beneficiary,
            caller: msg.sender
        });

        // Mint the equivalent amount of the project's token for the holder.
        token.mint({account: beneficiary, amount: count});
    }

deployERC20For.source:
function deployERC20For(
        uint256 projectId,
        string calldata name,
        string calldata symbol,
        bytes32 salt
    )
        external
        override
        onlyControllerOf(projectId)
        returns (IJBToken token)
    {
        // There must be a name.
        if (bytes(name).length == 0) revert JBTokens_EmptyName({projectId: projectId});

        // There must be a symbol.
        if (bytes(symbol).length == 0) revert JBTokens_EmptySymbol({projectId: projectId});

        // The project shouldn't already have a token.
        if (tokenOf[projectId] != IJBToken(address(0))) revert JBTokens_ProjectAlreadyHasToken(tokenOf[projectId]);

        token = salt == bytes32(0)
            ? IJBToken(Clones.clone(address(TOKEN)))
            : IJBToken(
                Clones.cloneDeterministic({
                    implementation: address(TOKEN), salt: keccak256(abi.encode(msg.sender, salt))
                })
            );

        // Store the token contract.
        tokenOf[projectId] = token;

        // Store the project for the token.
        projectIdOf[token] = projectId;

        emit DeployERC20({
            projectId: projectId, token: token, name: name, symbol: symbol, salt: salt, caller: msg.sender
        });

        // Initialize the token.
        token.initialize({name: name, symbol: symbol, tokensAddress: address(this)});
    }

mintFor.source:
function mintFor(
        address holder,
        uint256 projectId,
        uint256 count
    )
        external
        override
        onlyControllerOf(projectId)
        returns (IJBToken token)
    {
        // Get a reference to the project's current token.
        token = tokenOf[projectId];

        // Save a reference to whether there a token exists.
        bool tokensWereClaimed = token != IJBToken(address(0));

        // Cache the total supply to avoid a redundant external call on revert.
        uint256 supply = totalSupplyOf(projectId);

        // The total supply after minting can't exceed the maximum value storable in a uint208.
        if (supply + count > type(uint208).max) {
            revert JBTokens_OverflowAlert({value: supply + count, limit: type(uint208).max});
        }

        if (tokensWereClaimed) {
            // If tokens should be claimed, mint tokens into the holder's wallet.
            token.mint({account: holder, amount: count});
        } else {
            // Otherwise, add the tokens to their credits and the credit supply.
            creditBalanceOf[holder][projectId] += count;
            totalCreditSupplyOf[projectId] += count;
        }

        emit Mint({
            holder: holder, projectId: projectId, count: count, tokensWereClaimed: tokensWereClaimed, caller: msg.sender
        });
    }

setTokenFor.source:
function setTokenFor(uint256 projectId, IJBToken token) external override onlyControllerOf(projectId) {
        // Can't set to the zero address.
        if (token == IJBToken(address(0))) revert JBTokens_EmptyToken(projectId);

        // Can't set a token if the project is already associated with another token.
        if (tokenOf[projectId] != IJBToken(address(0))) revert JBTokens_ProjectAlreadyHasToken(tokenOf[projectId]);

        // Can't set a token if it's already associated with another project.
        if (projectIdOf[token] != 0) revert JBTokens_TokenAlreadyBeingUsed(projectIdOf[token]);

        // Can't change to a token that doesn't use 18 decimals.
        if (token.decimals() != 18) revert JBTokens_TokensMustHave18Decimals(token.decimals());

        // Make sure the token can be added to the project its being added to.
        if (!token.canBeAddedTo(projectId)) revert JBTokens_TokenCantBeAdded(projectId);

        // Store the new token.
        tokenOf[projectId] = token;

        // Store the project for the token.
        projectIdOf[token] = projectId;

        emit SetToken({projectId: projectId, token: token, caller: msg.sender});
    }

setTokenMetadataFor.source:
function setTokenMetadataFor(
        uint256 projectId,
        string calldata name,
        string calldata symbol
    )
        external
        override
        onlyControllerOf(projectId)
    {
        // Get a reference to the project's current token.
        IJBToken token = tokenOf[projectId];

        // The project must have a token contract attached.
        if (token == IJBToken(address(0))) revert JBTokens_TokenNotFound({projectId: projectId});

        // There must be a name.
        if (bytes(name).length == 0) revert JBTokens_EmptyName({projectId: projectId});

        // There must be a symbol.
        if (bytes(symbol).length == 0) revert JBTokens_EmptySymbol({projectId: projectId});

        emit SetTokenMetadata({projectId: projectId, name: name, symbol: symbol, caller: msg.sender});

        // Set the name and symbol.
        token.setMetadata({name: name, symbol: symbol});
    }

transferCreditsFrom.source:
function transferCreditsFrom(
        address holder,
        uint256 projectId,
        address recipient,
        uint256 count
    )
        external
        override
        onlyControllerOf(projectId)
    {
        // Get a reference to the holder's unclaimed project token balance.
        uint256 creditBalance = creditBalanceOf[holder][projectId];

        // The holder must have enough unclaimed tokens to transfer.
        if (count > creditBalance) revert JBTokens_InsufficientCredits(count, creditBalance);

        // Subtract from the holder's unclaimed token balance.
        unchecked {
            creditBalanceOf[holder][projectId] = creditBalance - count;
        }

        // Add the unclaimed project tokens to the recipient's balance.
        creditBalanceOf[recipient][projectId] += count;

        emit TransferCredits({
            holder: holder, projectId: projectId, recipient: recipient, count: count, caller: msg.sender
        });
    }

totalBalanceOf.source:
function totalBalanceOf(address holder, uint256 projectId) external view override returns (uint256 balance) {
        // Get a reference to the holder's credits for the project.
        balance = creditBalanceOf[holder][projectId];

        // Get a reference to the project's current token.
        IJBToken token = tokenOf[projectId];

        // If the project has a current token, add the holder's balance to the total.
        if (token != IJBToken(address(0))) {
            balance += token.balanceOf(holder);
        }
    }

totalSupplyOf.source:
function totalSupplyOf(uint256 projectId) public view override returns (uint256 totalSupply) {
        // Get a reference to the total supply of the project's credits
        totalSupply = totalCreditSupplyOf[projectId];

        // Get a reference to the project's current token.
        IJBToken token = tokenOf[projectId];

        // If the project has a current token, add its total supply to the total.
        if (token != IJBToken(address(0))) {
            totalSupply += token.totalSupply();
        }
    }

queueFor.source:
function queueFor(
        uint256 projectId,
        uint256 duration,
        uint256 weight,
        uint256 weightCutPercent,
        IJBRulesetApprovalHook approvalHook,
        uint256 metadata,
        uint256 mustStartAtOrAfter
    )
        external
        override
        onlyControllerOf(projectId)
        returns (JBRuleset memory)
    {
        // Duration must fit in a uint32.
        if (duration > type(uint32).max) revert JBRulesets_InvalidRulesetDuration(duration, type(uint32).max);

        // Weight cut percent must be less than or equal to 100%.
        if (weightCutPercent > JBConstants.MAX_WEIGHT_CUT_PERCENT) {
            revert JBRulesets_InvalidWeightCutPercent({percent: weightCutPercent});
        }

        // Weight must fit into a uint112.
        if (weight > type(uint112).max) revert JBRulesets_InvalidWeight(weight, type(uint112).max);

        // If the start date is not set, set it to be the current timestamp.
        if (mustStartAtOrAfter == 0) {
            mustStartAtOrAfter = block.timestamp;
        }

        // Make sure the min start date fits in a uint48, and that the start date of the following ruleset will also fit
        // within the max.
        if (mustStartAtOrAfter + duration > type(uint48).max) {
            revert JBRulesets_InvalidRulesetEndTime({timestamp: mustStartAtOrAfter + duration, limit: type(uint48).max});
        }

        // Approval hook should be a valid contract, supporting the correct interface
        if (approvalHook != IJBRulesetApprovalHook(address(0))) {
            // Revert if there isn't a contract at the address
            if (address(approvalHook).code.length == 0) revert JBRulesets_InvalidRulesetApprovalHook(approvalHook);

            // Make sure the approval hook supports the expected interface.
            try approvalHook.supportsInterface(type(IJBRulesetApprovalHook).interfaceId) returns (bool doesSupport) {
                if (!doesSupport) revert JBRulesets_InvalidRulesetApprovalHook(approvalHook); // Contract exists at the
                // address but
                // with the
                // wrong interface
            } catch {
                revert JBRulesets_InvalidRulesetApprovalHook({hook: approvalHook}); // No ERC165 support
            }
        }

        // Get a reference to the latest ruleset's ID.
        uint256 latestId = latestRulesetIdOf[projectId];

        // The new rulesetId timestamp is now, or an increment from now if the current timestamp is taken.
        // forge-lint: disable-next-line(block-timestamp)
        uint256 rulesetId = latestId >= block.timestamp ? latestId + 1 : block.timestamp;

        // Set up the ruleset by configuring intrinsic properties.
        _configureIntrinsicPropertiesFor({
            projectId: projectId, rulesetId: rulesetId, weight: weight, mustStartAtOrAfter: mustStartAtOrAfter
        });

        // Efficiently stores the ruleset's user-defined properties.
        // If all user config properties are zero, no need to store anything as the default value will have the same
        // outcome.
        if (approvalHook != IJBRulesetApprovalHook(address(0)) || duration > 0 || weightCutPercent > 0) {
            // approval hook in bits 0-159 bytes.
            uint256 packed = uint160(address(approvalHook));

            // duration in bits 160-191 bytes.
            packed |= duration << 160;

            // weightCutPercent in bits 192-223 bytes.
            packed |= weightCutPercent << 192;

            // Set in storage.
            _packedUserPropertiesOf[projectId][rulesetId] = packed;
        }

        // Set the metadata if needed.
        if (metadata > 0) _metadataOf[projectId][rulesetId] = metadata;

        emit RulesetQueued({
            rulesetId: rulesetId,
            projectId: projectId,
            duration: duration,
            weight: weight,
            weightCutPercent: weightCutPercent,
            approvalHook: approvalHook,
            metadata: metadata,
            mustStartAtOrAfter: mustStartAtOrAfter,
            caller: msg.sender
        });

        // Return the struct for the new ruleset's ID, with metadata.
        return _getStructFor({projectId: projectId, rulesetId: rulesetId, withMetadata: true});
    }

updateRulesetWeightCache.source:
function updateRulesetWeightCache(uint256 projectId, uint256 rulesetId) external override {
        // Get the target ruleset.
        JBRuleset memory targetRuleset =
            _getStructFor({projectId: projectId, rulesetId: rulesetId, withMetadata: false});

        // Nothing to cache if the target ruleset doesn't have a duration or a weight cut percent.
        if (targetRuleset.duration == 0 || targetRuleset.weightCutPercent == 0) return;

        // Get a reference to the current cache.
        JBRulesetWeightCache storage cache = _weightCacheOf[projectId][targetRuleset.id];

        // Determine the largest start timestamp the cache can be filled to.
        // Cap the advance to the cache lookup threshold per call to stay within the iteration limit in
        // deriveWeightFrom.
        // Multiple calls are needed to advance the cache for large cycle gaps.
        uint256 maxStart = targetRuleset.start + (cache.weightCutMultiple + _WEIGHT_CUT_MULTIPLE_CACHE_LOOKUP_THRESHOLD)
            * targetRuleset.duration;

        // Determine the start timestamp to derive a weight from for the cache.
        // forge-lint: disable-next-line(block-timestamp)
        uint256 start = block.timestamp < maxStart ? block.timestamp : maxStart;

        // The difference between the start of the latest queued ruleset and the start of the ruleset we're caching the
        // weight of.
        uint256 startDistance = start - targetRuleset.start;

        // Calculate the weight cut multiple.
        uint168 weightCutMultiple;
        unchecked {
            // forge-lint: disable-next-line(unsafe-typecast)
            weightCutMultiple = uint168(startDistance / targetRuleset.duration);
        }

        // Store the new values.
        cache.weight = uint112(
            deriveWeightFrom({
                projectId: projectId,
                baseRulesetStart: targetRuleset.start,
                baseRulesetDuration: targetRuleset.duration,
                baseRulesetWeight: targetRuleset.weight,
                baseRulesetWeightCutPercent: targetRuleset.weightCutPercent,
                baseRulesetCacheId: targetRuleset.id,
                start: start
            })
        );
        cache.weightCutMultiple = weightCutMultiple;

        emit WeightCacheUpdated({
            projectId: projectId, weight: cache.weight, weightCutMultiple: weightCutMultiple, caller: msg.sender
        });
    }

allOf.source:
function allOf(
        uint256 projectId,
        uint256 startingId,
        uint256 size
    )
        external
        view
        override
        returns (JBRuleset[] memory rulesets)
    {
        // If no starting ID was provided, set it to the latest ruleset's ID.
        if (startingId == 0) startingId = latestRulesetIdOf[projectId];

        // Keep a reference to the number of rulesets being returned.
        uint256 count = 0;

        // Keep a reference to the starting ruleset (metadata not needed — only counting).
        JBRuleset memory ruleset = _getStructFor({projectId: projectId, rulesetId: startingId, withMetadata: false});

        // First, count the number of rulesets to include in the result by iterating backwards from the starting
        // ruleset.
        while (ruleset.id != 0 && count < size) {
            // Increment the counter.
            count++;

            // Iterate to the ruleset it was based on.
            ruleset = _getStructFor({projectId: projectId, rulesetId: ruleset.basedOnId, withMetadata: false});
        }

        // Keep a reference to the array of rulesets that'll be populated.
        rulesets = new JBRuleset[](count);

        // Return an empty array if there are no rulesets to return.
        if (count == 0) {
            return rulesets;
        }

        // Reset the ruleset being iterated on to the starting ruleset, now with metadata for the return array.
        ruleset = _getStructFor({projectId: projectId, rulesetId: startingId, withMetadata: true});

        // Set the counter.
        uint256 i;

        // Populate the array of rulesets to return.
        while (i < count) {
            // Add the ruleset to the array.
            rulesets[i++] = ruleset;

            // Get the ruleset it was based on if needed, with metadata for the return array.
            if (i != count) {
                ruleset = _getStructFor({projectId: projectId, rulesetId: ruleset.basedOnId, withMetadata: true});
            }
        }
    }

currentApprovalStatusForLatestRulesetOf.source:
function currentApprovalStatusForLatestRulesetOf(uint256 projectId)
        external
        view
        override
        returns (JBApprovalStatus)
    {
        // Get a reference to the latest ruleset ID.
        uint256 rulesetId = latestRulesetIdOf[projectId];

        // Resolve the struct for the latest ruleset, with metadata (forwarded to the external approval hook).
        JBRuleset memory ruleset = _getStructFor({projectId: projectId, rulesetId: rulesetId, withMetadata: true});

        return _approvalStatusOf({projectId: projectId, ruleset: ruleset});
    }

currentOf.source:
function currentOf(uint256 projectId) external view override returns (JBRuleset memory ruleset) {
        // If the project does not have a ruleset, return an empty struct.
        if (latestRulesetIdOf[projectId] == 0) {
            return _getStructFor({projectId: 0, rulesetId: 0, withMetadata: false});
        }

        // Get a reference to the currently approvable ruleset's ID.
        uint256 rulesetId = _currentlyApprovableRulesetIdOf(projectId);

        // If a currently approvable ruleset exists...
        if (rulesetId != 0) {
            // Resolve the struct for the currently approvable ruleset, with metadata (forwarded to external hooks
            // and potentially returned).
            ruleset = _getStructFor({projectId: projectId, rulesetId: rulesetId, withMetadata: true});

            // Get a reference to the approval status.
            JBApprovalStatus approvalStatus = _approvalStatusOf({projectId: projectId, ruleset: ruleset});

            // Check to see if this ruleset's approval hook is approved if it exists.
            // If so, return it.
            if (approvalStatus == JBApprovalStatus.Approved || approvalStatus == JBApprovalStatus.Empty) {
                return ruleset;
            }

            // If it hasn't been approved, set the ruleset configuration to be the configuration of the ruleset that
            // it's based on,
            // which carries the last approved configuration.
            rulesetId = ruleset.basedOnId;

            // Keep a reference to its ruleset, with metadata (used by `_simulateCycledRulesetBasedOn` and may be
            // returned).
            ruleset = _getStructFor({projectId: projectId, rulesetId: rulesetId, withMetadata: true});
        } else {
            // No upcoming ruleset found that is currently approvable,
            // so use the latest ruleset ID.
            rulesetId = latestRulesetIdOf[projectId];

            // Get the struct for the latest ID, with metadata (forwarded to external hooks and may be returned).
            ruleset = _getStructFor({projectId: projectId, rulesetId: rulesetId, withMetadata: true});

            // Get a reference to the approval status.
            JBApprovalStatus approvalStatus = _approvalStatusOf({projectId: projectId, ruleset: ruleset});

            // While the ruleset has an approval hook that isn't approved or if it hasn't yet started, get a reference
            // to the ruleset that the latest is based on, which has the latest approved configuration.
            while (
                (approvalStatus != JBApprovalStatus.Approved && approvalStatus != JBApprovalStatus.Empty)
                    // forge-lint: disable-next-line(block-timestamp)
                    || block.timestamp < ruleset.start
            ) {
                rulesetId = ruleset.basedOnId;
                ruleset = _getStructFor({projectId: projectId, rulesetId: rulesetId, withMetadata: true});
                approvalStatus = _approvalStatusOf({projectId: projectId, ruleset: ruleset});
            }
        }

        // If the base has no duration, it's still the current one.
        if (ruleset.duration == 0) return ruleset;

        // Return a simulation of the current ruleset.
        return _simulateCycledRulesetBasedOn({projectId: projectId, baseRuleset: ruleset, allowMidRuleset: true});
    }

