upcomingOf.source:
function upcomingOf(uint256 projectId) external view override returns (JBRuleset memory ruleset) {
        // If the project does not have a latest ruleset, return an empty struct.
        if (latestRulesetIdOf[projectId] == 0) {
            return _getStructFor({projectId: 0, rulesetId: 0, withMetadata: false});
        }

        // Get a reference to the upcoming approvable ruleset's ID.
        uint256 upcomingApprovableRulesetId = _upcomingApprovableRulesetIdOf(projectId);

        // Keep a reference to its approval status.
        JBApprovalStatus approvalStatus;

        // If an upcoming approvable ruleset has been queued, and its approval status is Approved or ApprovalExpected,
        // return its ruleset struct
        if (upcomingApprovableRulesetId != 0) {
            ruleset = _getStructFor({projectId: projectId, rulesetId: upcomingApprovableRulesetId, withMetadata: true});

            // Get a reference to the approval status.
            approvalStatus = _approvalStatusOf({projectId: projectId, ruleset: ruleset});

            // If the approval hook is empty, expects approval, or has approved the ruleset, return it.
            if (
                approvalStatus == JBApprovalStatus.Approved || approvalStatus == JBApprovalStatus.ApprovalExpected
                    || approvalStatus == JBApprovalStatus.Empty
            ) return ruleset;

            // Resolve the ruleset for the ruleset the upcoming approvable ruleset was based on, with metadata
            // (used by `_simulateCycledRulesetBasedOn`).
            ruleset = _getStructFor({projectId: projectId, rulesetId: ruleset.basedOnId, withMetadata: true});
        } else {
            // Resolve the ruleset for the latest queued ruleset, with metadata (forwarded to external hooks and used
            // by `_simulateCycledRulesetBasedOn`).
            ruleset = _getStructFor({projectId: projectId, rulesetId: latestRulesetIdOf[projectId], withMetadata: true});

            // If the latest ruleset starts in the future, it must start in the distant future
            // Since it's not the upcoming approvable ruleset. In this case, base the upcoming ruleset on the base
            // ruleset.
            // forge-lint: disable-next-line(block-timestamp)
            while (ruleset.start > block.timestamp) {
                ruleset = _getStructFor({projectId: projectId, rulesetId: ruleset.basedOnId, withMetadata: true});
            }
        }

        // There's no queued if the current has a duration of 0.
        if (ruleset.duration == 0) return _getStructFor({projectId: 0, rulesetId: 0, withMetadata: false});

        // Get a reference to the approval status.
        approvalStatus = _approvalStatusOf({projectId: projectId, ruleset: ruleset});

        // Check to see if this ruleset's approval hook hasn't failed.
        // If so, return a ruleset based on it.
        if (approvalStatus == JBApprovalStatus.Approved || approvalStatus == JBApprovalStatus.Empty) {
            return _simulateCycledRulesetBasedOn({projectId: projectId, baseRuleset: ruleset, allowMidRuleset: false});
        }

        // Get the ruleset of its base ruleset, which carries the last approved configuration. Metadata is needed by
        // `_simulateCycledRulesetBasedOn`.
        ruleset = _getStructFor({projectId: projectId, rulesetId: ruleset.basedOnId, withMetadata: true});

        // There's no queued if the base, which must still be the current, has a duration of 0.
        if (ruleset.duration == 0) return _getStructFor({projectId: 0, rulesetId: 0, withMetadata: false});

        // Return a simulated cycled ruleset.
        return _simulateCycledRulesetBasedOn({projectId: projectId, baseRuleset: ruleset, allowMidRuleset: false});
    }

deriveCycleNumberFrom.source:
function deriveCycleNumberFrom(
        uint256 baseRulesetCycleNumber,
        uint256 baseRulesetStart,
        uint256 baseRulesetDuration,
        uint256 start
    )
        public
        pure
        returns (uint256)
    {
        // A subsequent ruleset to one with a duration of 0 should be the next number.
        if (baseRulesetDuration == 0) {
            return baseRulesetCycleNumber + 1;
        }

        // The difference between the start of the base ruleset and the proposed start.
        uint256 startDistance = start - baseRulesetStart;

        // Find the number of base rulesets that fit in the start distance.
        return baseRulesetCycleNumber + (startDistance / baseRulesetDuration);
    }

deriveStartFrom.source:
function deriveStartFrom(
        uint256 baseRulesetStart,
        uint256 baseRulesetDuration,
        uint256 mustStartAtOrAfter
    )
        public
        pure
        returns (uint256 start)
    {
        // A subsequent ruleset to one with a duration of 0 should start as soon as possible.
        if (baseRulesetDuration == 0) return mustStartAtOrAfter;

        // The time when the ruleset immediately after the specified ruleset starts.
        uint256 nextImmediateStart = baseRulesetStart + baseRulesetDuration;

        // If the next immediate start is now or in the future, return it.
        if (nextImmediateStart >= mustStartAtOrAfter) {
            return nextImmediateStart;
        }

        // The amount of seconds since the `mustStartAtOrAfter` time which results in a start time that might satisfy
        // the specified limits.
        uint256 timeFromImmediateStartMultiple = (mustStartAtOrAfter - nextImmediateStart) % baseRulesetDuration;

        // A reference to the first possible start timestamp.
        start = mustStartAtOrAfter - timeFromImmediateStartMultiple;

        // Add increments of duration as necessary to satisfy the threshold.
        while (mustStartAtOrAfter > start) {
            start += baseRulesetDuration;
        }
    }

deriveWeightFrom.source:
function deriveWeightFrom(
        uint256 projectId,
        uint256 baseRulesetStart,
        uint256 baseRulesetDuration,
        uint256 baseRulesetWeight,
        uint256 baseRulesetWeightCutPercent,
        uint256 baseRulesetCacheId,
        uint256 start
    )
        public
        view
        returns (uint256 weight)
    {
        // A subsequent ruleset to one with a duration of 0 should have the next possible weight.
        if (baseRulesetDuration == 0) {
            return mulDiv({
                x: baseRulesetWeight,
                y: JBConstants.MAX_WEIGHT_CUT_PERCENT - baseRulesetWeightCutPercent,
                denominator: JBConstants.MAX_WEIGHT_CUT_PERCENT
            });
        }

        // The weight should be based off the base ruleset's weight.
        weight = baseRulesetWeight;

        // If the weight cut percent is 0, the weight doesn't change.
        if (baseRulesetWeightCutPercent == 0) return weight;

        // The difference between the start of the base ruleset and the proposed start.
        uint256 startDistance = start - baseRulesetStart;

        // Apply the base ruleset's weight cut percent for each ruleset that has passed.
        uint256 weightCutMultiple;
        unchecked {
            weightCutMultiple = startDistance / baseRulesetDuration; // Non-null duration is excluded above
        }

        // Check the cache if needed.
        if (baseRulesetCacheId > 0 && weightCutMultiple > _WEIGHT_CUT_MULTIPLE_CACHE_LOOKUP_THRESHOLD) {
            // Get a cached weight for the rulesetId.
            JBRulesetWeightCache memory cache = _weightCacheOf[projectId][baseRulesetCacheId];

            // If a cached value is available, use it.
            if (cache.weightCutMultiple > 0) {
                // Set the starting weight to be the cached value.
                weight = cache.weight;

                // Set the weight cut multiple to be the difference between the cached value and the total weight cut
                // multiple that should be applied.
                weightCutMultiple -= cache.weightCutMultiple;
            }
        }

        // If too many iterations remain after cache lookup, require the cache to be populated first.
        // This prevents gas exhaustion for short-duration rulesets with large cycle counts.
        if (weightCutMultiple > _WEIGHT_CUT_MULTIPLE_CACHE_LOOKUP_THRESHOLD) {
            revert JBRulesets_WeightCacheRequired({projectId: projectId});
        }

        // Cache the cut factor and max percent to avoid recomputing each iteration.
        uint256 cutFactor = JBConstants.MAX_WEIGHT_CUT_PERCENT - baseRulesetWeightCutPercent;
        uint256 maxPercent = JBConstants.MAX_WEIGHT_CUT_PERCENT;

        for (uint256 i; i < weightCutMultiple;) {
            // Base the new weight on the specified ruleset's weight.
            weight = mulDiv({x: weight, y: cutFactor, denominator: maxPercent});

            // The calculation doesn't need to continue if the weight is 0.
            if (weight == 0) break;
            unchecked {
                ++i;
            }
        }
    }

_configureIntrinsicPropertiesFor.source:
function _configureIntrinsicPropertiesFor(
        uint256 projectId,
        uint256 rulesetId,
        uint256 weight,
        uint256 mustStartAtOrAfter
    )
        internal
    {
        // Keep a reference to the project's latest ruleset's ID.
        uint256 latestId = latestRulesetIdOf[projectId];

        // If the project doesn't have a ruleset yet, initialize one.
        if (latestId == 0) {
            // Use an empty ruleset as the base.
            return _initializeRulesetFor({
                projectId: projectId,
                baseRuleset: _getStructFor({projectId: 0, rulesetId: 0, withMetadata: false}),
                rulesetId: rulesetId,
                mustStartAtOrAfter: mustStartAtOrAfter,
                weight: weight
            });
        }

        // Get a reference to the latest ruleset's struct, with metadata because `_approvalStatusOf` forwards the
        // struct to external approval hooks.
        JBRuleset memory baseRuleset = _getStructFor({projectId: projectId, rulesetId: latestId, withMetadata: true});

        // Get a reference to the approval status.
        JBApprovalStatus approvalStatus = _approvalStatusOf({projectId: projectId, ruleset: baseRuleset});

        // If the base ruleset has started but wasn't approved if an approval hook exists
        // OR it hasn't started but is currently approved
        // OR it hasn't started but it is likely to be approved and takes place before the proposed one,
        // set the struct to be the ruleset it's based on, which carries the latest approved ruleset.
        if (
            // forge-lint: disable-next-line(block-timestamp)
            (block.timestamp >= baseRuleset.start
                    && approvalStatus != JBApprovalStatus.Approved
                    && approvalStatus != JBApprovalStatus.Empty)
                // forge-lint: disable-next-line(block-timestamp)
                || (block.timestamp < baseRuleset.start
                    && mustStartAtOrAfter < baseRuleset.start + baseRuleset.duration
                    && approvalStatus != JBApprovalStatus.Approved)
                // forge-lint: disable-next-line(block-timestamp)
                || (block.timestamp < baseRuleset.start
                    && mustStartAtOrAfter >= baseRuleset.start + baseRuleset.duration
                    && approvalStatus != JBApprovalStatus.Approved
                    && approvalStatus != JBApprovalStatus.ApprovalExpected
                    && approvalStatus != JBApprovalStatus.Empty)
        ) {
            // Metadata not needed — the fallback ruleset is only used for intrinsic fields (start, basedOnId, etc.)
            // and not forwarded to any external approval hook.
            baseRuleset = _getStructFor({projectId: projectId, rulesetId: baseRuleset.basedOnId, withMetadata: false});
        }

        // Make sure the ruleset starts after the base ruleset.
        if (baseRuleset.start > mustStartAtOrAfter) mustStartAtOrAfter = baseRuleset.start;

        // The time when the duration of the base ruleset's approval hook has finished.
        // If the provided ruleset has no approval hook, return 0 (no constraint on start time).
        uint256 timestampAfterApprovalHook;
        if (baseRuleset.approvalHook != IJBRulesetApprovalHook(address(0))) {
            try baseRuleset.approvalHook.DURATION() returns (uint256 duration) {
                timestampAfterApprovalHook = rulesetId + duration;
            } catch {
                // If DURATION() reverts, treat as no approval hook constraint.
                timestampAfterApprovalHook = 0;
            }
        }

        _initializeRulesetFor({
            projectId: projectId,
            baseRuleset: baseRuleset,
            rulesetId: rulesetId,
            // Can only start after the approval hook.
            mustStartAtOrAfter: timestampAfterApprovalHook > mustStartAtOrAfter
                ? timestampAfterApprovalHook
                : mustStartAtOrAfter,
            weight: weight
        });
    }

_initializeRulesetFor.source:
function _initializeRulesetFor(
        uint256 projectId,
        JBRuleset memory baseRuleset,
        uint256 rulesetId,
        uint256 mustStartAtOrAfter,
        uint256 weight
    )
        internal
    {
        // If there is no base, initialize a first ruleset.
        if (baseRuleset.cycleNumber == 0) {
            // Set fresh intrinsic properties.
            _packAndStoreIntrinsicPropertiesOf({
                rulesetId: rulesetId,
                projectId: projectId,
                rulesetCycleNumber: 1,
                weight: weight,
                basedOnId: baseRuleset.id,
                start: mustStartAtOrAfter
            });
        } else {
            // Derive the correct next start time from the base.
            uint256 start = deriveStartFrom({
                baseRulesetStart: baseRuleset.start,
                baseRulesetDuration: baseRuleset.duration,
                mustStartAtOrAfter: mustStartAtOrAfter
            });

            // A weight of 1 is a special case that represents inheriting the cut weight of the previous
            // ruleset.
            weight = weight == 1
                ? deriveWeightFrom({
                    projectId: projectId,
                    baseRulesetStart: baseRuleset.start,
                    baseRulesetDuration: baseRuleset.duration,
                    baseRulesetWeight: baseRuleset.weight,
                    baseRulesetWeightCutPercent: baseRuleset.weightCutPercent,
                    baseRulesetCacheId: baseRuleset.id,
                    start: start
                })
                : weight;

            // Derive the correct ruleset cycle number.
            uint256 rulesetCycleNumber = deriveCycleNumberFrom({
                baseRulesetCycleNumber: baseRuleset.cycleNumber,
                baseRulesetStart: baseRuleset.start,
                baseRulesetDuration: baseRuleset.duration,
                start: start
            });

            // Update the intrinsic properties.
            _packAndStoreIntrinsicPropertiesOf({
                rulesetId: rulesetId,
                projectId: projectId,
                rulesetCycleNumber: rulesetCycleNumber,
                weight: weight,
                basedOnId: baseRuleset.id,
                start: start
            });
        }

        // Set the project's latest ruleset configuration.
        latestRulesetIdOf[projectId] = rulesetId;

        emit RulesetInitialized({
            rulesetId: rulesetId, projectId: projectId, basedOnId: baseRuleset.id, caller: msg.sender
        });
    }

_packAndStoreIntrinsicPropertiesOf.source:
function _packAndStoreIntrinsicPropertiesOf(
        uint256 rulesetId,
        uint256 projectId,
        uint256 rulesetCycleNumber,
        uint256 weight,
        uint256 basedOnId,
        uint256 start
    )
        internal
    {
        // `weight` in bits 0-111.
        uint256 packed = weight;

        // `basedOnId` in bits 112-159.
        packed |= basedOnId << 112;

        // `start` in bits 160-207.
        packed |= start << 160;

        // cycle number in bits 208-255.
        packed |= rulesetCycleNumber << 208;

        // Store the packed value.
        _packedIntrinsicPropertiesOf[projectId][rulesetId] = packed;
    }

_approvalStatusOf.source:
function _approvalStatusOf(uint256 projectId, JBRuleset memory ruleset) internal view returns (JBApprovalStatus) {
        // If there is no ruleset ID to check the approval hook of, the approval hook is empty.
        if (ruleset.basedOnId == 0) return JBApprovalStatus.Empty;

        // Read only the packed user properties to extract the approval hook address,
        // avoiding the cost of loading the full parent ruleset struct.
        uint256 packedUserProperties = _packedUserPropertiesOf[projectId][ruleset.basedOnId];
        // forge-lint: disable-next-line(unsafe-typecast)
        IJBRulesetApprovalHook approvalHook = IJBRulesetApprovalHook(address(uint160(packedUserProperties)));

        // If there is no approval hook, it's considered empty.
        if (approvalHook == IJBRulesetApprovalHook(address(0))) {
            return JBApprovalStatus.Empty;
        }

        // Return the approval hook's approval status.
        // Wrap in try/catch to prevent a reverting approval hook from permanently freezing the project.
        // Note: A malicious hook that consumes all gas (e.g. infinite loop) could still DoS via gas exhaustion.
        // This is accepted risk since the project owner chose their own approval hook.
        try approvalHook.approvalStatusOf({projectId: projectId, ruleset: ruleset}) returns (JBApprovalStatus status) {
            return status;
        } catch {
            return JBApprovalStatus.Failed;
        }
    }

_currentlyApprovableRulesetIdOf.source:
function _currentlyApprovableRulesetIdOf(uint256 projectId) internal view returns (uint256) {
        // Get a reference to the project's latest ruleset.
        uint256 rulesetId = latestRulesetIdOf[projectId];

        // Get the struct for the latest ruleset (metadata not needed — only traversal fields are checked).
        JBRuleset memory ruleset = _getStructFor({projectId: projectId, rulesetId: rulesetId, withMetadata: false});

        // Loop through all most recently queued rulesets until an approvable one is found, or we've proven one can't
        // exist.
        do {
            // If the latest ruleset is expired, return an empty ruleset.
            // A ruleset with a duration of 0 cannot expire.
            // forge-lint: disable-next-line(block-timestamp)
            if (ruleset.duration != 0 && block.timestamp >= ruleset.start + ruleset.duration) {
                return 0;
            }

            // Return the ruleset's `rulesetId` if it has started.
            // forge-lint: disable-next-line(block-timestamp)
            if (block.timestamp >= ruleset.start) {
                return ruleset.id;
            }

            ruleset = _getStructFor({projectId: projectId, rulesetId: ruleset.basedOnId, withMetadata: false});
        } while (ruleset.cycleNumber != 0);

        return 0;
    }

_getStructFor.source:
function _getStructFor(
        uint256 projectId,
        uint256 rulesetId,
        bool withMetadata
    )
        internal
        view
        returns (JBRuleset memory ruleset)
    {
        // Return an empty ruleset if the specified `rulesetId` is 0.
        if (rulesetId == 0) return ruleset;

        // forge-lint: disable-next-line(unsafe-typecast)
        ruleset.id = uint48(rulesetId);

        uint256 packedIntrinsicProperties = _packedIntrinsicPropertiesOf[projectId][rulesetId];

        // `weight` in bits 0-111 bits.
        // forge-lint: disable-next-line(unsafe-typecast)
        ruleset.weight = uint112(packedIntrinsicProperties);
        // `basedOnId` in bits 112-159 bits.
        // forge-lint: disable-next-line(unsafe-typecast)
        ruleset.basedOnId = uint48(packedIntrinsicProperties >> 112);
        // `start` in bits 160-207 bits.
        // forge-lint: disable-next-line(unsafe-typecast)
        ruleset.start = uint48(packedIntrinsicProperties >> 160);
        // `cycleNumber` in bits 208-255 bits.
        // forge-lint: disable-next-line(unsafe-typecast)
        ruleset.cycleNumber = uint48(packedIntrinsicProperties >> 208);

        uint256 packedUserProperties = _packedUserPropertiesOf[projectId][rulesetId];

        // approval hook in bits 0-159 bits.
        // forge-lint: disable-next-line(unsafe-typecast)
        ruleset.approvalHook = IJBRulesetApprovalHook(address(uint160(packedUserProperties)));
        // `duration` in bits 160-191 bits.
        // forge-lint: disable-next-line(unsafe-typecast)
        ruleset.duration = uint32(packedUserProperties >> 160);
        // weight cut percent in bits 192-223 bits.
        // forge-lint: disable-next-line(unsafe-typecast)
        ruleset.weightCutPercent = uint32(packedUserProperties >> 192);

        // Load metadata only when needed — saves one cold SLOAD (~2,100 gas) for traversal-only paths.
        if (withMetadata) ruleset.metadata = _metadataOf[projectId][rulesetId];
    }

_simulateCycledRulesetBasedOn.source:
function _simulateCycledRulesetBasedOn(
        uint256 projectId,
        JBRuleset memory baseRuleset,
        bool allowMidRuleset
    )
        internal
        view
        returns (JBRuleset memory)
    {
        // Get the distance from the current time to the start of the next possible ruleset.
        // If the simulated ruleset must not yet have started, the start time of the simulated ruleset must be in the
        // future.
        uint256 mustStartAtOrAfter = !allowMidRuleset
            ? block.timestamp + 1
            // forge-lint: disable-next-line(block-timestamp)
            : baseRuleset.duration >= block.timestamp ? 1 : block.timestamp - baseRuleset.duration + 1;

        // Calculate what the start time should be.
        uint256 start = deriveStartFrom({
            baseRulesetStart: baseRuleset.start,
            baseRulesetDuration: baseRuleset.duration,
            mustStartAtOrAfter: mustStartAtOrAfter
        });

        // Calculate what the cycle number should be.
        uint256 rulesetCycleNumber = deriveCycleNumberFrom({
            baseRulesetCycleNumber: baseRuleset.cycleNumber,
            baseRulesetStart: baseRuleset.start,
            baseRulesetDuration: baseRuleset.duration,
            start: start
        });

        return JBRuleset({
            // forge-lint: disable-next-line(unsafe-typecast)
            cycleNumber: uint48(rulesetCycleNumber),
            id: baseRuleset.id,
            basedOnId: baseRuleset.basedOnId,
            // forge-lint: disable-next-line(unsafe-typecast)
            start: uint48(start),
            duration: baseRuleset.duration,
            weight: uint112(
                deriveWeightFrom({
                    projectId: projectId,
                    baseRulesetStart: baseRuleset.start,
                    baseRulesetDuration: baseRuleset.duration,
                    baseRulesetWeight: baseRuleset.weight,
                    baseRulesetWeightCutPercent: baseRuleset.weightCutPercent,
                    baseRulesetCacheId: baseRuleset.id,
                    start: start
                })
            ),
            weightCutPercent: baseRuleset.weightCutPercent,
            approvalHook: baseRuleset.approvalHook,
            metadata: baseRuleset.metadata
        });
    }

_upcomingApprovableRulesetIdOf.source:
function _upcomingApprovableRulesetIdOf(uint256 projectId) internal view returns (uint256 rulesetId) {
        // Get a reference to the ID of the project's latest ruleset.
        rulesetId = latestRulesetIdOf[projectId];

        // Get the struct for the latest ruleset (metadata not needed — only traversal fields are checked).
        JBRuleset memory ruleset = _getStructFor({projectId: projectId, rulesetId: rulesetId, withMetadata: false});

        // There is no upcoming ruleset if the latest ruleset has already started.
        // forge-lint: disable-next-line(block-timestamp)
        if (block.timestamp >= ruleset.start) return 0;

        // If this is the first ruleset, it is queued.
        if (ruleset.cycleNumber == 1) return rulesetId;

        // Get a reference to the ID of the ruleset the latest ruleset was based on.
        uint256 basedOnId = ruleset.basedOnId;

        // Get the necessary properties for the base ruleset.
        JBRuleset memory baseRuleset;

        // Find the base ruleset that is not still queued.
        while (true) {
            baseRuleset = _getStructFor({projectId: projectId, rulesetId: basedOnId, withMetadata: false});

            // If the base ruleset starts in the future,
            // forge-lint: disable-next-line(block-timestamp)
            if (block.timestamp < baseRuleset.start) {
                // Set the `rulesetId` to the one found.
                rulesetId = baseRuleset.id;
                // Check the ruleset it was based on in the next iteration.
                basedOnId = baseRuleset.basedOnId;
            } else {
                // Break out of the loop when a base ruleset which has already started is found.
                break;
            }
        }

        // Get the ruleset struct for the ID found (metadata not needed — only `start` and `duration` are checked).
        ruleset = _getStructFor({projectId: projectId, rulesetId: rulesetId, withMetadata: false});

        // If the latest ruleset doesn't start until after another base ruleset return 0.
        // forge-lint: disable-next-line(block-timestamp)
        if (baseRuleset.duration != 0 && block.timestamp < ruleset.start - baseRuleset.duration) {
            return 0;
        }
    }

setSplitGroupsOf.source:
function setSplitGroupsOf(
        uint256 projectId,
        uint256 rulesetId,
        JBSplitGroup[] calldata splitGroups
    )
        external
        override
    {
        // Cache whether the controller check has already passed to avoid repeated external calls.
        bool controllerChecked;

        // Set each grouped splits. Access calldata directly to avoid copying each split group to memory.
        for (uint256 i; i < splitGroups.length;) {
            // Self-auth: lower 160 bits must match msg.sender AND upper 96 bits must be non-zero.
            // GroupIds with zero upper bits are reserved for protocol use (e.g. terminal payout groups)
            // and always require controller authorization to prevent token contracts from hijacking payouts.
            bool isSelfManaged =
                splitGroups[i].groupId >> 160 != 0 && address(uint160(splitGroups[i].groupId)) == msg.sender;

            if (!isSelfManaged && !controllerChecked) {
                _onlyControllerOf(projectId);
                controllerChecked = true;
            }

            // Set the splits for the group.
            _setSplitsOf({
                projectId: projectId,
                rulesetId: rulesetId,
                groupId: splitGroups[i].groupId,
                splits: splitGroups[i].splits
            });
            unchecked {
                ++i;
            }
        }
    }

splitsOf.source:
function splitsOf(
        uint256 projectId,
        uint256 rulesetId,
        uint256 groupId
    )
        external
        view
        override
        returns (JBSplit[] memory splits)
    {
        splits = _getStructsFor({projectId: projectId, rulesetId: rulesetId, groupId: groupId});

        // Use the default splits if there aren't any for the ruleset.
        if (splits.length == 0) {
            splits = _getStructsFor({projectId: projectId, rulesetId: FALLBACK_RULESET_ID, groupId: groupId});
        }
    }

_setSplitsOf.source:
function _setSplitsOf(uint256 projectId, uint256 rulesetId, uint256 groupId, JBSplit[] memory splits) internal {
        // Get a reference to the current split structs within the project, ruleset, and group.
        JBSplit[] memory currentSplits = _getStructsFor({projectId: projectId, rulesetId: rulesetId, groupId: groupId});

        // Keep a reference to the current number of splits within the group.
        uint256 numberOfCurrentSplits = currentSplits.length;

        // Check to see if all locked splits are included in the array of splits which is being set.
        // Duplicate locked splits must be preserved with the same multiplicity. Otherwise a table with two identical
        // locked splits could be collapsed into one matching split and one unrelated split while each old split sees
        // the same new match.
        for (uint256 i; i < numberOfCurrentSplits;) {
            // If not locked, continue.
            // forge-lint: disable-next-line(block-timestamp)
            if (block.timestamp < currentSplits[i].lockedUntil) {
                uint256 requiredCount;
                for (uint256 j; j < numberOfCurrentSplits;) {
                    if (
                        // forge-lint: disable-next-line(block-timestamp)
                        block.timestamp < currentSplits[j].lockedUntil
                            && _isLockedSplitIncluded({split: currentSplits[j], lockedSplit: currentSplits[i]})
                    ) {
                        ++requiredCount;
                    }
                    unchecked {
                        ++j;
                    }
                }

                if (_includedLockedSplitCount({splits: splits, lockedSplit: currentSplits[i]}) < requiredCount) {
                    revert JBSplits_PreviousLockedSplitsNotIncluded({projectId: projectId, rulesetId: rulesetId});
                }
            }
            unchecked {
                ++i;
            }
        }

        // Add up all the `percent`s to make sure their total is under 100%.
        uint256 percentTotal;

        // Keep a reference to the number of splits to set.
        uint256 numberOfSplits = splits.length;

        for (uint256 i; i < numberOfSplits;) {
            // Set the split being iterated on.
            JBSplit memory split = splits[i];

            // The percent should be greater than 0.
            if (split.percent == 0) {
                revert JBSplits_ZeroSplitPercent({
                    projectId: projectId, rulesetId: rulesetId, groupId: groupId, splitIndex: i
                });
            }

            // Add to the `percent` total.
            percentTotal += split.percent;

            // Ensure the total does not exceed 100%.
            if (percentTotal > JBConstants.SPLITS_TOTAL_PERCENT) {
                revert JBSplits_TotalPercentExceeds100({
                    projectId: projectId, rulesetId: rulesetId, groupId: groupId, percentTotal: percentTotal
                });
            }

            uint256 packedSplitParts1;

            // Pack `percent` in bits 0-31.
            packedSplitParts1 = split.percent;
            // Pack `projectId` in bits 32-95.
            packedSplitParts1 |= uint256(split.projectId) << 32;
            // Pack `beneficiary` in bits 96-255.
            packedSplitParts1 |= uint256(uint160(address(split.beneficiary))) << 96;

            // Store the first split part.
            _packedSplitParts1Of[projectId][rulesetId][groupId][i] = packedSplitParts1;

            // If there's data to store in the second packed split part, pack and store.
            if (split.preferAddToBalance || split.lockedUntil > 0 || split.hook != IJBSplitHook(address(0))) {
                // Pack `preferAddToBalance` in bit 0.
                uint256 packedSplitParts2 = split.preferAddToBalance ? 1 : 0;
                // Pack `lockedUntil` in bits 1-48.
                packedSplitParts2 |= uint256(split.lockedUntil) << 1;
                // Pack `hook` in bits 49-208.
                packedSplitParts2 |= uint256(uint160(address(split.hook))) << 49;

                // Store the second split part.
                _packedSplitParts2Of[projectId][rulesetId][groupId][i] = packedSplitParts2;
            } else if (_packedSplitParts2Of[projectId][rulesetId][groupId][i] > 0) {
                // If there's a value stored in the indexed position, delete it.
                delete _packedSplitParts2Of[projectId][rulesetId][groupId][i];
            }

            emit SetSplit({
                projectId: projectId, rulesetId: rulesetId, groupId: groupId, split: split, caller: msg.sender
            });
            unchecked {
                ++i;
            }
        }

        // Store the number of splits for the project, ruleset, and group.
        _splitCountOf[projectId][rulesetId][groupId] = numberOfSplits;

        // Clean up stale storage slots if the new split count is less than the previous count.
        // This zeroes out leftover packed data to reclaim gas via storage refunds.
        for (uint256 i = numberOfSplits; i < numberOfCurrentSplits;) {
            delete _packedSplitParts1Of[projectId][rulesetId][groupId][i];
            delete _packedSplitParts2Of[projectId][rulesetId][groupId][i];
            unchecked {
                ++i;
            }
        }
    }

_getStructsFor.source:
function _getStructsFor(
        uint256 projectId,
        uint256 rulesetId,
        uint256 groupId
    )
        internal
        view
        returns (JBSplit[] memory)
    {
        // Get a reference to the number of splits that need to be added to the returned array.
        uint256 splitCount = _splitCountOf[projectId][rulesetId][groupId];

        // Initialize an array to be returned that has the appropriate length.
        JBSplit[] memory splits = new JBSplit[](splitCount);

        // Loop through each split and unpack the values into structs.
        for (uint256 i; i < splitCount;) {
            // Get a reference to the first part of the split's packed data.
            uint256 packedSplitPart1 = _packedSplitParts1Of[projectId][rulesetId][groupId][i];

            // Populate the split struct.
            JBSplit memory split;

            // `percent` in bits 0-31.
            // forge-lint: disable-next-line(unsafe-typecast)
            split.percent = uint32(packedSplitPart1);
            // `projectId` in bits 32-95.
            // forge-lint: disable-next-line(unsafe-typecast)
            split.projectId = uint64(packedSplitPart1 >> 32);
            // `beneficiary` in bits 96-255.
            // forge-lint: disable-next-line(unsafe-typecast)
            split.beneficiary = payable(address(uint160(packedSplitPart1 >> 96)));

            // Get a reference to the second part of the split's packed data.
            uint256 packedSplitPart2 = _packedSplitParts2Of[projectId][rulesetId][groupId][i];

            // If there's anything in it, unpack.
            if (packedSplitPart2 > 0) {
                // `preferAddToBalance` in bit 0.
                split.preferAddToBalance = packedSplitPart2 & 1 == 1;
                // `lockedUntil` in bits 1-48.
                // forge-lint: disable-next-line(unsafe-typecast)
                split.lockedUntil = uint48(packedSplitPart2 >> 1);
                // `hook` in bits 49-208.
                // forge-lint: disable-next-line(unsafe-typecast)
                split.hook = IJBSplitHook(address(uint160(packedSplitPart2 >> 49)));
            }

            // Add the split to the value being returned.
            splits[i] = split;
            unchecked {
                ++i;
            }
        }

        return splits;
    }

_includedLockedSplitCount.source:
function _includedLockedSplitCount(
        JBSplit[] memory splits,
        JBSplit memory lockedSplit
    )
        internal
        pure
        returns (uint256 count)
    {
        // Keep a reference to the number of splits.
        uint256 numberOfSplits = splits.length;

        for (uint256 i; i < numberOfSplits;) {
            if (_isLockedSplitIncluded({split: splits[i], lockedSplit: lockedSplit})) ++count;
            unchecked {
                ++i;
            }
        }
    }

_isLockedSplitIncluded.source:
function _isLockedSplitIncluded(JBSplit memory split, JBSplit memory lockedSplit) internal pure returns (bool) {
        // Allow the lock to be extended.
        return split.percent == lockedSplit.percent && split.beneficiary == lockedSplit.beneficiary
            && split.hook == lockedSplit.hook && split.projectId == lockedSplit.projectId
            && split.preferAddToBalance == lockedSplit.preferAddToBalance
            && split.lockedUntil >= lockedSplit.lockedUntil;
    }

setPermissionsFor.source:
function setPermissionsFor(address account, JBPermissionsData calldata permissionsData) external override {
        // Pack the permission IDs into a uint256.
        uint256 packed = _packedPermissions(permissionsData.permissionIds);

        // Make sure the 0 permission is not set.
        if (_includesPermission({permissions: packed, permissionId: 0})) {
            revert JBPermissions_NoZeroPermission({
                account: account, operator: permissionsData.operator, projectId: permissionsData.projectId
            });
        }

        // Cache the sender.
        address msgSender = _msgSender();

        // Enforce permissions. ROOT operators are allowed to set permissions so long as they are not setting another
        // ROOT permission or setting permissions for a wildcard project ID.
        if (
            msgSender != account
                && (_includesPermission({permissions: packed, permissionId: JBPermissionIds.ROOT})
                    || permissionsData.projectId == WILDCARD_PROJECT_ID
                    || !hasPermission({
                        operator: msgSender,
                        account: account,
                        projectId: permissionsData.projectId,
                        permissionId: JBPermissionIds.ROOT,
                        includeRoot: true,
                        includeWildcardProjectId: true
                    }))
        ) {
            revert JBPermissions_Unauthorized({
                account: account,
                operator: msgSender,
                projectId: permissionsData.projectId,
                permissionId: JBPermissionIds.ROOT
            });
        }

        // Store the new value.
        permissionsOf[permissionsData.operator][account][permissionsData.projectId] = packed;

        emit OperatorPermissionsSet({
            operator: permissionsData.operator,
            account: account,
            projectId: permissionsData.projectId,
            permissionIds: permissionsData.permissionIds,
            packed: packed,
            caller: msgSender
        });
    }

hasPermissions.source:
function hasPermissions(
        address operator,
        address account,
        uint256 projectId,
        uint256[] calldata permissionIds,
        bool includeRoot,
        bool includeWildcardProjectId
    )
        external
        view
        override
        returns (bool)
    {
        // If the ROOT permission is set and should be included, return true.
        if (
            includeRoot
                && (_includesPermission({
                        permissions: permissionsOf[operator][account][projectId], permissionId: JBPermissionIds.ROOT
                    })
                    || (includeWildcardProjectId
                        && _includesPermission({
                            permissions: permissionsOf[operator][account][WILDCARD_PROJECT_ID],
                            permissionId: JBPermissionIds.ROOT
                        })))
        ) {
            return true;
        }

        // Keep a reference to the permission item being checked.
        uint256 operatorAccountProjectPermissions = permissionsOf[operator][account][projectId];

        // Keep a reference to the wildcard project permissions.
        uint256 operatorAccountWildcardProjectPermissions =
            includeWildcardProjectId ? permissionsOf[operator][account][WILDCARD_PROJECT_ID] : 0;

        // Returns true for empty permission arrays by design (vacuous truth). An empty set of
        // required permissions is trivially satisfied. Callers should validate non-empty permission arrays if needed.
        for (uint256 i; i < permissionIds.length;) {
            // Set the permission being iterated on.
            uint256 permissionId = permissionIds[i];

            // Indexes above 255 don't exist
            if (permissionId > 255) revert JBPermissions_PermissionIdOutOfBounds(permissionId);

            // Check each permissionId
            if (
                !_includesPermission({permissions: operatorAccountProjectPermissions, permissionId: permissionId})
                    && !_includesPermission({
                        permissions: operatorAccountWildcardProjectPermissions, permissionId: permissionId
                    })
            ) {
                return false;
            }
            unchecked {
                ++i;
            }
        }
        return true;
    }

hasPermission.source:
function hasPermission(
        address operator,
        address account,
        uint256 projectId,
        uint256 permissionId,
        bool includeRoot,
        bool includeWildcardProjectId
    )
        public
        view
        override
        returns (bool)
    {
        // Indexes above 255 don't exist
        if (permissionId > 255) revert JBPermissions_PermissionIdOutOfBounds(permissionId);

        // Cache both permission slots upfront to avoid redundant storage reads.
        uint256 projectPermissions = permissionsOf[operator][account][projectId];
        uint256 wildcardPermissions =
            includeWildcardProjectId ? permissionsOf[operator][account][WILDCARD_PROJECT_ID] : 0;

        // If the ROOT permission is set and should be included, return true.
        if (
            includeRoot
                && (_includesPermission({permissions: projectPermissions, permissionId: JBPermissionIds.ROOT})
                    || _includesPermission({permissions: wildcardPermissions, permissionId: JBPermissionIds.ROOT}))
        ) {
            return true;
        }

        // Otherwise return the t/f flag of the specified id.
        return _includesPermission({permissions: projectPermissions, permissionId: permissionId})
            || _includesPermission({permissions: wildcardPermissions, permissionId: permissionId});
    }

_includesPermission.source:
function _includesPermission(uint256 permissions, uint256 permissionId) internal pure returns (bool) {
        return ((permissions >> permissionId) & 1) == 1;
    }

_packedPermissions.source:
function _packedPermissions(uint8[] calldata permissionIds) internal pure returns (uint256 packed) {
        for (uint256 i; i < permissionIds.length;) {
            // Set the permission being iterated on.
            uint256 permissionId = permissionIds[i];

            // Turn on the bit at the ID.
            // forge-lint: disable-next-line(incorrect-shift)
            packed |= 1 << permissionId;
            unchecked {
                ++i;
            }
        }
    }

addPriceFeedFor.source:
function addPriceFeedFor(
        uint256 projectId,
        uint256 pricingCurrency,
        uint256 unitCurrency,
        IJBPriceFeed feed
    )
        external
        override
    {
        // Project 0 configures defaults for every project; each other project delegates feed configuration to its
        // controller.
        projectId == DEFAULT_PROJECT_ID ? _checkOwner() : _onlyControllerOf(projectId);

        if (pricingCurrency == 0) {
            revert JBPrices_ZeroPricingCurrency({projectId: projectId, pricingCurrency: pricingCurrency});
        }

        if (unitCurrency == 0) revert JBPrices_ZeroUnitCurrency({projectId: projectId, unitCurrency: unitCurrency});

        if (feed == IJBPriceFeed(address(0))) revert JBPrices_ZeroPriceFeed();

        // Only exact-direction duplicates are rejected. Opposite-direction feeds can coexist and are used when deriving
        // inverse prices.
        _requireNewPriceFeed({
            projectId: projectId, pricingCurrency: pricingCurrency, unitCurrency: unitCurrency, feed: feed
        });

        // Keep existing feeds immutable: appending preserves the primary feed and adds this feed as the last fallback.
        _priceFeedsFor[projectId][pricingCurrency][unitCurrency].push(feed);

        emit AddPriceFeed({
            projectId: projectId,
            pricingCurrency: pricingCurrency,
            unitCurrency: unitCurrency,
            feed: feed,
            caller: _msgSender()
        });
    }

