_sendAccountingSnapshotOverAMB.source:
function _sendAccountingSnapshotOverAMB(
        uint256 transportPayment,
        JBAccountingSnapshot memory snapshot
    )
        internal
        virtual
        override
    {
        // The OP messenger does not expect native transport payment for accounting-only messages.
        if (transportPayment != 0) {
            revert JBSucker_UnexpectedMsgValue({value: transportPayment});
        }

        OPMESSENGER.sendMessage({
            target: _toAddress(peer()),
            message: abi.encodeCall(JBSucker.fromRemoteAccounting, (snapshot)),
            // Scale the destination gas with the bundle so a larger mesh's accounting still stores in one relay.
            gasLimit: SafeCast.toUint32(_messagingGasLimit({accounts: snapshot.accounts}))
        });
    }

_sendRootOverAMB.source:
function _sendRootOverAMB(
        uint256 transportPayment,
        uint256,
        address token,
        uint256 amount,
        JBRemoteToken memory remoteToken,
        JBMessageRoot memory message
    )
        internal
        virtual
        override
    {
        uint256 nativeValue;

        // Revert if there's a `msg.value`. The OP bridge does not expect to be paid.
        if (transportPayment != 0) {
            revert JBSucker_UnexpectedMsgValue({value: transportPayment});
        }

        // Cache peer address to avoid redundant calls.
        address peerAddress = _toAddress(peer());

        // If the token is an ERC20, bridge it to the peer.
        // If the amount is `0` then we do not need to bridge any ERC20.
        if (token != JBConstants.NATIVE_TOKEN && amount != 0) {
            // Approve the tokens being bridged.
            SafeERC20.forceApprove({token: IERC20(token), spender: address(OPBRIDGE), value: amount});

            // Bridge the tokens to the peer sucker. Convert bytes32 types to address at the OP Bridge API boundary.
            OPBRIDGE.bridgeERC20To({
                localToken: token,
                remoteToken: _toAddress(remoteToken.addr),
                to: peerAddress,
                amount: amount,
                minGasLimit: remoteToken.minGas,
                extraData: bytes("")
            });

            SafeERC20.forceApprove({token: IERC20(token), spender: address(OPBRIDGE), value: 0});
        } else {
            // Otherwise, the token is the native token, and the amount will be sent as `msg.value`.
            nativeValue = amount;
        }

        // Send the message to the peer with the reclaimed ETH.
        OPMESSENGER.sendMessage{value: nativeValue}({
            target: peerAddress,
            message: abi.encodeCall(JBSucker.fromRemote, (message)),
            // Scale the destination gas with the bundle so a larger mesh's accounting still stores in one relay.
            gasLimit: SafeCast.toUint32(_messagingGasLimit({accounts: message.accounts}))
        });
    }

peerChainId.source:
function peerChainId() public view virtual override returns (uint256) {
        uint256 chainId = block.chainid;
        if (chainId == ARBChains.ETH_CHAINID) return ARBChains.ARB_CHAINID;
        if (chainId == ARBChains.ARB_CHAINID) return ARBChains.ETH_CHAINID;
        if (chainId == ARBChains.ETH_SEP_CHAINID) return ARBChains.ARB_SEP_CHAINID;
        if (chainId == ARBChains.ARB_SEP_CHAINID) return ARBChains.ETH_SEP_CHAINID;
        return 0;
    }

_approveGateway.source:
function _approveGateway(
        address approvalToken,
        address gatewayLookupToken,
        uint256 amount
    )
        internal
        returns (address gateway)
    {
        gateway = GATEWAYROUTER.getGateway(gatewayLookupToken);
        SafeERC20.forceApprove({token: IERC20(approvalToken), spender: gateway, value: amount});
    }

_createRetryableTicket.source:
function _createRetryableTicket(
        uint256 callTransportCost,
        uint256 nativeValue,
        uint256 maxSubmissionCost,
        uint256 maxFeePerGas,
        uint256 gasLimit,
        bytes memory data
    )
        internal
    {
        address peerAddress = _peerAddress();
        ARBINBOX.unsafeCreateRetryableTicket{value: callTransportCost + nativeValue}({
            to: peerAddress,
            l2CallValue: nativeValue,
            maxSubmissionCost: maxSubmissionCost,
            excessFeeRefundAddress: _msgSender(),
            callValueRefundAddress: peerAddress,
            gasLimit: gasLimit,
            maxFeePerGas: maxFeePerGas,
            data: data
        });
    }

_sendAccountingSnapshotOverAMB.source:
function _sendAccountingSnapshotOverAMB(
        uint256 transportPayment,
        JBAccountingSnapshot memory snapshot
    )
        internal
        override
    {
        // Build the calldata that will be sent to the peer. This calls `JBSucker.fromRemoteAccounting` remotely.
        bytes memory data = abi.encodeCall(JBSucker.fromRemoteAccounting, (snapshot));
        JBRemoteToken memory remoteToken;

        // Depending on which layer we are on, send the call to the other layer.
        if (LAYER == JBLayer.L1) {
            // L1→L2 requires transport payment for retryable tickets.
            if (transportPayment == 0) revert JBSucker_ExpectedMsgValue({msgValue: transportPayment});
            _toL2({
                token: JBConstants.NATIVE_TOKEN,
                transportPayment: transportPayment,
                amount: 0,
                data: data,
                remoteToken: remoteToken,
                gasLimit: _messagingGasLimit({accounts: snapshot.accounts})
            });
        } else {
            // L2→L1 via ArbSys is free — reject any transport payment.
            if (transportPayment != 0) revert JBSucker_UnexpectedMsgValue(transportPayment);
            _toL1({token: JBConstants.NATIVE_TOKEN, amount: 0, data: data, remoteToken: remoteToken});
        }
    }

_sendRootOverAMB.source:
function _sendRootOverAMB(
        uint256 transportPayment,
        uint256,
        address token,
        uint256 amount,
        JBRemoteToken memory remoteToken,
        JBMessageRoot memory message
    )
        internal
        override
    {
        // Build the calldata that will be send to the peer. This will call `JBSucker.fromRemote` on the remote peer.
        bytes memory data = abi.encodeCall(JBSucker.fromRemote, (message));

        // Depending on which layer we are on, send the call to the other layer.
        if (LAYER == JBLayer.L1) {
            // L1→L2 requires transport payment for retryable tickets.
            if (transportPayment == 0) revert JBSucker_ExpectedMsgValue({msgValue: transportPayment});
            _toL2({
                token: token,
                transportPayment: transportPayment,
                amount: amount,
                data: data,
                remoteToken: remoteToken,
                gasLimit: _messagingGasLimit({accounts: message.accounts})
            });
        } else {
            // L2→L1 via ArbSys is free — reject any transport payment.
            if (transportPayment != 0) revert JBSucker_UnexpectedMsgValue(transportPayment);
            _toL1({token: token, amount: amount, data: data, remoteToken: remoteToken});
        }
    }

_toL1.source:
function _toL1(address token, uint256 amount, bytes memory data, JBRemoteToken memory remoteToken) internal {
        uint256 nativeValue;

        // Cache peer address to avoid redundant calls.
        address peerAddress = _peerAddress();

        // If the token is an ERC-20, bridge it to the peer.
        // If the amount is `0` then we do not need to bridge any ERC20.
        if (token != JBConstants.NATIVE_TOKEN && amount != 0) {
            address gateway = _approveGateway({
                approvalToken: token, gatewayLookupToken: _toAddress(remoteToken.addr), amount: amount
            });

            // Convert bytes32 types to address at the Arbitrum bridge API boundary.
            IArbL2GatewayRouter(address(GATEWAYROUTER))
                .outboundTransfer({
                l1Token: _toAddress(remoteToken.addr), to: peerAddress, amount: amount, data: bytes("")
            });

            SafeERC20.forceApprove({token: IERC20(token), spender: gateway, value: 0});
        } else {
            // Otherwise, the token is the native token, and the amount will be sent as `msg.value`.
            nativeValue = amount;
        }

        // Send the message to the peer with the reclaimed ETH.
        // Address `100` is the ArbSys precompile address.
        ArbSys(address(100)).sendTxToL1{value: nativeValue}({destination: peerAddress, data: data});
    }

_toL2.source:
function _toL2(
        address token,
        uint256 transportPayment,
        uint256 amount,
        bytes memory data,
        JBRemoteToken memory remoteToken,
        uint256 gasLimit
    )
        internal
    {
        uint256 nativeValue;
        uint256 maxFeePerGas = block.basefee;
        uint256 callTransportCost;
        uint256 maxSubmissionCost;

        {
            maxSubmissionCost =
                ARBINBOX.calculateRetryableSubmissionFee({dataLength: data.length, baseFee: maxFeePerGas});

            // Tracks the cost for the call to the remote peer. Scaled to the bundle so a larger mesh's accounting
            // store does not run out of gas on the destination.
            callTransportCost = maxSubmissionCost + (gasLimit * maxFeePerGas);
        }

        // If the token is an ERC-20, bridge it to the peer.
        // If the amount is `0` then we do not need to bridge any ERC20.
        if (token != JBConstants.NATIVE_TOKEN && amount != 0) {
            address gateway;
            uint256 tokenTransportCost;
            uint256 maxSubmissionCostERC20;
            {
                // Get the exact calldata length the gateway will create for the retryable ticket.
                // The Arbitrum Inbox validates maxSubmissionCost against this actual payload, not the user data.
                gateway = GATEWAYROUTER.getGateway(token);
                uint256 outboundCalldataLength =
                    IL1ArbitrumGateway(gateway)
                .getOutboundCalldata({
                    token: token, from: address(this), to: _peerAddress(), amount: amount, data: bytes("")
                }).length;
                maxSubmissionCostERC20 = ARBINBOX.calculateRetryableSubmissionFee({
                    dataLength: outboundCalldataLength, baseFee: maxFeePerGas
                });
                tokenTransportCost = maxSubmissionCostERC20 + (remoteToken.minGas * maxFeePerGas);
            }

            // Ensure we bridge enough for gas costs on L2 side
            if (transportPayment < callTransportCost + tokenTransportCost) {
                revert JBArbitrumSucker_NotEnoughGas({
                    payment: transportPayment, cost: callTransportCost + tokenTransportCost
                });
            }

            {
                // The amount of left over transportPayment will be split over the two calls.
                uint256 transportPaymentRemainder = (transportPayment - callTransportCost - tokenTransportCost) / 2;
                tokenTransportCost += transportPaymentRemainder;
                callTransportCost += transportPaymentRemainder;
            }

            // Approve the tokens to be bridged.
            _approveGateway({approvalToken: token, gatewayLookupToken: token, amount: amount});

            // Perform the ERC-20 bridge transfer. Convert bytes32 peer to address at the Arbitrum bridge API boundary.
            IArbL1GatewayRouter(address(GATEWAYROUTER)).outboundTransferCustomRefund{value: tokenTransportCost}({
                token: token,
                refundTo: _msgSender(),
                to: _peerAddress(),
                amount: amount,
                maxGas: remoteToken.minGas,
                gasPriceBid: maxFeePerGas,
                data: bytes(abi.encode(maxSubmissionCostERC20, bytes("")))
            });

            SafeERC20.forceApprove({token: IERC20(token), spender: gateway, value: 0});
        } else {
            // Ensure we bridge enough for gas costs on L2 side
            if (transportPayment < callTransportCost) {
                revert JBArbitrumSucker_NotEnoughGas({payment: transportPayment, cost: callTransportCost});
            }

            // If the token is the native token then we only need to do a single call.
            // So it should use all of the transportPayment.
            callTransportCost = transportPayment;

            // Otherwise, the token is the native token, and the amount will be sent as `msg.value`.
            nativeValue = amount;
        }

        // Create the retryable ticket containing the merkleRoot.
        // We call unsafe as we do not want the refund address to be aliased to L2.
        // The above check is the same check that makes it `safeCreateRetryableTicket`.

        // Convert bytes32 peer to address at the Arbitrum inbox API boundary.
        _createRetryableTicket({
            callTransportCost: callTransportCost,
            nativeValue: nativeValue,
            maxSubmissionCost: maxSubmissionCost,
            maxFeePerGas: maxFeePerGas,
            gasLimit: gasLimit,
            data: data
        });
    }

_isRemotePeer.source:
function _isRemotePeer(address sender) internal view override returns (bool) {
        // Convert the bytes32 peer to an address for comparison with EVM bridge contracts.
        address peerAddress = _peerAddress();

        // If we are the L1 peer,
        if (LAYER == JBLayer.L1) {
            IBridge bridge = ARBINBOX.bridge();
            // Check that the sender is the bridge and that the outbox has our peer as the sender.
            return sender == address(bridge) && peerAddress == IOutbox(bridge.activeOutbox()).l2ToL1Sender();
        }

        // If we are the L2 peer, check using the `AddressAliasHelper`.
        return sender == AddressAliasHelper.applyL1ToL2Alias(peerAddress);
    }

ccipReceive.source:
function ccipReceive(Client.Any2EVMMessage calldata any2EvmMessage) external virtual override {
        // Use msg.sender (not _msgSender()) because the CCIP router never uses ERC2771 meta-transactions.
        // Using _msgSender() would allow a trusted forwarder to spoof the router address via the
        // ERC-2771 calldata suffix.
        if (msg.sender != address(CCIP_ROUTER)) revert JBSucker_NotPeer(_toBytes32(msg.sender));

        // Decode the sender address from the CCIP message.
        address origin = abi.decode(any2EvmMessage.sender, (address));

        // Make sure that the message came from our peer.
        if (origin != _peerAddress() || any2EvmMessage.sourceChainSelector != REMOTE_CHAIN_SELECTOR) {
            revert JBSucker_NotPeer({caller: _toBytes32(origin)});
        }

        // Discriminate message type: abi.encode(uint8 type, bytes payload).
        (uint8 messageType, bytes memory payload) = abi.decode(any2EvmMessage.data, (uint8, bytes));

        // Handle root messages (merkle tree updates with bridged assets).
        if (messageType == _CCIP_MSG_TYPE_ROOT) {
            // Decode the root message from the payload.
            JBMessageRoot memory root = abi.decode(payload, (JBMessageRoot));

            // Cross-check the delivered tokens against the advertised root before recording anything.
            //
            // The send-side guarantees at most one entry in `destTokenAmounts`: length 0 for zero-value batches,
            // length 1 for value-bearing batches. A compromised peer (or a malformed CCIP delivery) that violates
            // these invariants would otherwise let `fromRemote` record a root advertising more value than was
            // bridged, letting later claims mint project tokens against unrelated balance until the inbox runs dry.
            // `JBSwapCCIPSucker.ccipReceive` already enforces equivalent reverts for the swap variant; mirror
            // them here so both variants share a single defensive baseline.
            uint256 deliveryCount = any2EvmMessage.destTokenAmounts.length;
            if (deliveryCount > 1) {
                revert JBCCIPSucker_UnexpectedDeliveredTokens(deliveryCount);
            }
            if (deliveryCount == 0) {
                if (root.amount > 0) revert JBCCIPSucker_PositiveRootWithoutDelivery(root.amount);
            } else {
                Client.EVMTokenAmount calldata delivered = any2EvmMessage.destTokenAmounts[0];
                bool rootIsNativeToken = root.token == bytes32(uint256(uint160(JBConstants.NATIVE_TOKEN)));

                // For NATIVE_TOKEN bridges the delivered ERC-20 is the wrapped native token (CCIP cannot transport
                // raw native), so require the router-reported wrapped native address before unwrapping. For
                // everything else, the delivered token must equal the local mapped token the root advertises.
                address expectedToken =
                    rootIsNativeToken ? address(CCIP_ROUTER.getWrappedNative()) : _toAddress(root.token);
                if (delivered.token != expectedToken) {
                    revert JBCCIPSucker_WrongDeliveredToken({delivered: delivered.token, expected: expectedToken});
                }

                // The bridged amount must back at least the value the root advertises. A short delivery against a
                // positive root is the structural twin of "no delivery + positive root" — both leave the inbox
                // recording more claimable value than it actually holds.
                if (delivered.amount < root.amount) {
                    revert JBCCIPSucker_UnderDeliveredAmount({delivered: delivered.amount, rootAmount: root.amount});
                }
            }

            // Only unwrap wrapped native token when the root targets native token (not when claiming it as ERC-20).
            if (root.token == bytes32(uint256(uint160(JBConstants.NATIVE_TOKEN)))) {
                JBCCIPLib.unwrapReceivedTokens({
                    ccipRouter: CCIP_ROUTER, destTokenAmounts: any2EvmMessage.destTokenAmounts
                });
            }

            // Forward the root message to this contract's fromRemote handler.
            this.fromRemote(root);
        } else if (messageType == _CCIP_MSG_TYPE_ACCOUNTING) {
            // Accounting-only messages must not carry tokens; transported value belongs exclusively to root messages.
            uint256 deliveryCount = any2EvmMessage.destTokenAmounts.length;
            if (deliveryCount != 0) {
                revert JBCCIPSucker_UnexpectedDeliveredTokens(deliveryCount);
            }

            JBAccountingSnapshot memory snapshot = abi.decode(payload, (JBAccountingSnapshot));

            // Forward the accounting message to this contract's authenticated accounting handler.
            this.fromRemoteAccounting(snapshot);
        } else {
            revert JBCCIPSucker_UnknownMessageType({messageType: messageType});
        }
    }

