setEnsNamePartsFor.source:
function setEnsNamePartsFor(uint256 chainId, uint256 projectId, string[] memory parts) external override {
        // Cache the number of ENS name parts.
        uint256 partsLength = parts.length;

        // Make sure there are ENS name parts.
        if (partsLength == 0) {
            revert JBProjectHandles_NoParts({chainId: chainId, projectId: projectId, caller: _msgSender()});
        }

        // Make sure no provided parts are empty or contain unsafe ASCII bytes.
        for (uint256 i; i < partsLength; i++) {
            string memory part = parts[i];
            bytes memory partBytes = bytes(part);

            if (partBytes.length == 0) {
                revert JBProjectHandles_EmptyNamePart({parts: parts});
            }

            // Reject "eth" as a name part to prevent ambiguous handles (e.g. "foo.eth.eth").
            if (keccak256(partBytes) == _ETH_NAME_PART_HASH) {
                revert JBProjectHandles_EthPartNotAllowed({parts: parts});
            }

            // Reject ASCII control characters (< 0x20), DEL (0x7F), and dots. Higher-byte Unicode handling is
            // delegated to off-chain ENSIP-15 normalization — see contract NatSpec.
            for (uint256 j; j < partBytes.length; j++) {
                bytes1 b = partBytes[j];
                if (b < 0x20 || b == 0x7f || b == ".") {
                    revert JBProjectHandles_InvalidNamePart({part: part});
                }
            }
        }

        // Store the parts.
        _ensNamePartsOf[chainId][projectId][_msgSender()] = parts;

        emit SetEnsNameParts({
            chainId: chainId, projectId: projectId, handle: _formatHandle(parts), parts: parts, caller: _msgSender()
        });
    }

ensNamePartsOf.source:
function ensNamePartsOf(
        uint256 chainId,
        uint256 projectId,
        address setter
    )
        external
        view
        override
        returns (string[] memory)
    {
        return _ensNamePartsOf[chainId][projectId][setter];
    }

handleOf.source:
function handleOf(
        uint256 chainId,
        uint256 projectId,
        address setter
    )
        external
        view
        override
        returns (string memory)
    {
        // Get a reference to the project's ENS name parts.
        string[] memory ensNameParts = _ensNamePartsOf[chainId][projectId][setter];

        // Return an empty string if not found.
        if (ensNameParts.length == 0) return "";

        // Compute the hash of the handle.
        bytes32 hashedName = _namehash(ensNameParts);

        // If the ENS registry has no code (chain without ENS), return empty string instead of reverting.
        if (address(ENS_REGISTRY).code.length == 0) return "";

        // Get the resolver for this handle from the trusted ENS registry.
        address textResolver = ENS_REGISTRY.resolver(hashedName);

        // If the handle is not a registered ENS, return empty string.
        if (textResolver == address(0)) return "";

        // Find the text record that the ENS name is mapped to. Resolvers are name-owner controlled, so use a low-level
        // call to soft-fail malformed return data the same way as a reverting resolver.
        string memory textRecord = _textRecordOf({textResolver: textResolver, hashedName: hashedName});

        // Return empty string if text record from ENS name doesn't match `projectId` and `chainId`.
        if (
            keccak256(bytes(textRecord))
                != keccak256(bytes(string.concat(Strings.toString(chainId), ":", Strings.toString(projectId))))
        ) return "";

        // Format the handle from the name parts.
        return _formatHandle(ensNameParts);
    }

_formatHandle.source:
function _formatHandle(string[] memory ensNameParts) internal pure returns (string memory handle) {
        // Cache the number of ENS name parts.
        uint256 partsLength = ensNameParts.length;

        // Concatenate each name part.
        for (uint256 i = 1; i <= partsLength; i++) {
            // Compute the handle.
            handle = string(abi.encodePacked(handle, ensNameParts[partsLength - i]));

            // Add a dot if this part isn't the last.
            if (i < partsLength) handle = string(abi.encodePacked(handle, "."));
        }
    }

_msgData.source:
function _msgData() internal view override returns (bytes calldata) {
        return ERC2771Context._msgData();
    }

_msgSender.source:
function _msgSender() internal view override returns (address sender) {
        return ERC2771Context._msgSender();
    }

_namehash.source:
function _namehash(string[] memory ensNameParts) internal pure returns (bytes32 namehash) {
        // Hash the trailing "eth" suffix.
        namehash = keccak256(abi.encodePacked(namehash, keccak256(abi.encodePacked("eth"))));

        // Build the visible handle for hashing.
        bytes memory handle = bytes(_formatHandle(ensNameParts));

        // Get a reference to the current label's end. Labels are hashed from right to left.
        uint256 labelEnd = handle.length;

        // Hash each dot-separated label.
        for (uint256 i = handle.length; i > 0; i--) {
            if (handle[i - 1] != ".") continue;

            namehash =
                keccak256(abi.encodePacked(namehash, keccak256(_slice({input: handle, start: i, end: labelEnd}))));
            labelEnd = i - 1;
        }

        // Hash the leftmost label.
        namehash = keccak256(abi.encodePacked(namehash, keccak256(_slice({input: handle, start: 0, end: labelEnd}))));
    }

_slice.source:
function _slice(bytes memory input, uint256 start, uint256 end) internal pure returns (bytes memory output) {
        output = new bytes(end - start);

        for (uint256 i; i < output.length; i++) {
            output[i] = input[start + i];
        }
    }

_textRecordOf.source:
function _textRecordOf(address textResolver, bytes32 hashedName) internal view returns (string memory textRecord) {
        // Resolver contracts are controlled by the ENS name owner, so use a low-level call instead of a typed
        // `try/catch`. A typed return would still ABI-decode a successful-but-malformed response in this frame.
        bytes memory callData = abi.encodeWithSelector(ITextResolver.text.selector, hashedName, TEXT_KEY);

        // Copy at most the offset word, the length word, and `_MAX_TEXT_RECORD_LENGTH` string bytes from the response.
        // A name-owner-controlled resolver could return an arbitrarily large response; copying it all before applying
        // the cap would let the resolver drive this read's gas (memory expansion grows with return-data size). Bounding
        // the copy at the call site keeps a hostile, oversized response from exhausting gas or reverting the lookup.
        uint256 maxCopy = 64 + _MAX_TEXT_RECORD_LENGTH;

        bool success;
        uint256 returnSize;
        uint256 offset;
        uint256 length;
        bytes memory result;

        // Forward only a bounded gas stipend. A standard `text` read is cheap, so this caps a hostile resolver's
        // ability to burn this read's gas. `gas()` is forwarded only when it is already below the stipend (EIP-150
        // would clamp it anyway), so a well-behaved resolver never sees less gas than it does today.
        uint256 stipend = gasleft();
        if (stipend > _RESOLVER_GAS_LIMIT) stipend = _RESOLVER_GAS_LIMIT;

        assembly {
            // staticcall with a zero output region so the EVM does not auto-copy the full response into memory.
            success := staticcall(stipend, textResolver, add(callData, 32), mload(callData), 0, 0)

            // The total size the resolver actually returned, even though only `maxCopy` bytes are copied below.
            returnSize := returndatasize()

            // Allocate a scratch buffer and copy at most `maxCopy` bytes of the response into it.
            result := mload(0x40)
            let copySize := returnSize
            if gt(copySize, maxCopy) { copySize := maxCopy }
            mstore(0x40, add(result, add(copySize, 32)))
            mstore(result, copySize)
            returndatacopy(add(result, 32), 0, copySize)

            // First two return words: the offset to the string data and its byte length.
            if iszero(lt(copySize, 64)) {
                offset := mload(add(result, 32))
                length := mload(add(result, 64))
            }
        }

        // The ABI encoding for one dynamic `string` return needs at least an offset word and a length word.
        if (!success || returnSize < 64) return "";

        // A standard single-string return has offset 32. Cap the length, and require the resolver to have actually
        // returned the bytes it claims (`returnSize >= 64 + length`) so a truncated response soft-fails too. The cap
        // prevents a name-owner-controlled resolver from returning a huge, valid ABI string that readers must copy
        // before the later `chainId:projectId` equality check rejects it.
        if (offset != 32 || length > _MAX_TEXT_RECORD_LENGTH || returnSize < 64 + length) return "";

        bytes memory textBytes = bytes(textRecord = new string(length));
        for (uint256 i; i < length;) {
            // Copy the string bytes by hand from the bounded buffer; malformed resolver data soft-fails above.
            textBytes[i] = result[64 + i];
            unchecked {
                ++i;
            }
        }
    }

registerAddress.source:
function registerAddress(address deployer, uint256 nonce) external override {
        // Calculate the address of the contract, assuming it was deployed using `create` with the specified nonce.
        address hook = _addressFrom({origin: deployer, nonce: nonce});

        // Register the contract using the calculated address.
        _registerAddress({addr: hook, deployer: deployer});
    }

function registerAddress(address deployer, bytes32 salt, bytes calldata bytecode) external override {
        // Calculate the address of the contract using the provided `create2` salt and deployment bytecode.
        address hook =
            address(uint160(uint256(keccak256(abi.encodePacked(bytes1(0xff), deployer, salt, keccak256(bytecode))))));

        // Register the contract using the calculated address.
        _registerAddress({addr: hook, deployer: deployer});
    }

_registerAddress.source:
function _registerAddress(address addr, address deployer) internal {
        // The registry only records non-zero deployers.
        if (deployer == address(0)) revert JBAddressRegistry_ZeroDeployer(deployer);
        // The address must already contain runtime code before it can be registered.
        if (addr.code.length == 0) revert JBAddressRegistry_AddressNotDeployed(addr);
        // Each address can only be registered once.
        if (deployerOf[addr] != address(0)) revert JBAddressRegistry_AlreadyRegistered(addr);

        deployerOf[addr] = deployer;

        emit AddressRegistered({addr: addr, deployer: deployer, caller: msg.sender});
    }

_addressFrom.source:
function _addressFrom(address origin, uint256 nonce) internal pure returns (address addr) {
        if (nonce > type(uint64).max) revert JBAddressRegistry_NonceTooLarge(nonce);

        bytes memory data;
        if (nonce == 0x00) {
            data = abi.encodePacked(bytes1(0xd6), bytes1(0x94), origin, bytes1(0x80));
        } else if (nonce <= 0x7f) {
            // forge-lint: disable-next-line(unsafe-typecast)
            data = abi.encodePacked(bytes1(0xd6), bytes1(0x94), origin, uint8(nonce));
        } else if (nonce <= 0xff) {
            // forge-lint: disable-next-line(unsafe-typecast)
            data = abi.encodePacked(bytes1(0xd7), bytes1(0x94), origin, bytes1(0x81), uint8(nonce));
        } else if (nonce <= 0xffff) {
            // forge-lint: disable-next-line(unsafe-typecast)
            data = abi.encodePacked(bytes1(0xd8), bytes1(0x94), origin, bytes1(0x82), uint16(nonce));
        } else if (nonce <= 0xffffff) {
            // forge-lint: disable-next-line(unsafe-typecast)
            data = abi.encodePacked(bytes1(0xd9), bytes1(0x94), origin, bytes1(0x83), uint24(nonce));
        } else if (nonce <= 0xffffffff) {
            // forge-lint: disable-next-line(unsafe-typecast)
            data = abi.encodePacked(bytes1(0xda), bytes1(0x94), origin, bytes1(0x84), uint32(nonce));
        } else if (nonce <= 0xffffffffff) {
            // Nonces above uint32 need 5 payload bytes, so RLP moves to the 0x85 length prefix.
            // forge-lint: disable-next-line(unsafe-typecast)
            data = abi.encodePacked(bytes1(0xdb), bytes1(0x94), origin, bytes1(0x85), uint40(nonce));
        } else if (nonce <= 0xffffffffffff) {
            // Keep extending the nonce payload width as values cross the uint40 boundary.
            // forge-lint: disable-next-line(unsafe-typecast)
            data = abi.encodePacked(bytes1(0xdc), bytes1(0x94), origin, bytes1(0x86), uint48(nonce));
        } else if (nonce <= 0xffffffffffffff) {
            // This branch covers the last intermediate RLP width before the full uint64 payload.
            // forge-lint: disable-next-line(unsafe-typecast)
            data = abi.encodePacked(bytes1(0xdd), bytes1(0x94), origin, bytes1(0x87), uint56(nonce));
        } else {
            // The largest supported CREATE nonce uses the 8-byte uint64 payload with a 0x88 length prefix.
            // forge-lint: disable-next-line(unsafe-typecast)
            data = abi.encodePacked(bytes1(0xde), bytes1(0x94), origin, bytes1(0x88), uint64(nonce));
        }
        // forge-lint: disable-next-line(asm-keccak256)
        bytes32 hash = keccak256(data);
        assembly {
            mstore(0, hash)
            addr := mload(0)
        }
    }

buildTerminalConfigurations.source:
function buildTerminalConfigurations(
        IJBTerminal multiTerminal,
        IJBTerminal routerTerminalRegistry
    )
        public
        pure
        returns (JBAccountingContext[] memory accountingContextsToAccept)
    {
        multiTerminal;
        routerTerminalRegistry;

        accountingContextsToAccept = new JBAccountingContext[](1);
        accountingContextsToAccept[0] =
            JBAccountingContext({token: JBConstants.NATIVE_TOKEN, decimals: 18, currency: NATIVE_CURRENCY});
